var FacebookRemote = function(storage) 
{
	"use strict";
	// TODO:
	this.storage = storage;

	this.storage.encode = 'none';

	this.synchronous = false;
};

// Initialize the remote method
FacebookRemote.prototype.initialize = function(onSuccess, onFail) {
	"use strict";
	if(fbInstant.isInitialized()){
		onSuccess();
	} else {
		onFail();
	}
};

FacebookRemote.prototype.getUserId = function()
{
	'use strict';

	return fbInstant.playerID;
};

// Saving data (key and data are string).
FacebookRemote.prototype.saveData = function(key, data, onSuccess, onFail) 
{
	"use strict";

	fbInstant.extraSaveData(data, onSuccess, onFail);

	fbInstant.extraData = data;
};

// Loading data. When ready, process data is called with the data.
FacebookRemote.prototype.loadData = function(key, processData, onSuccess, onFail) 
{
	"use strict";

	var self = this;

	fbInstant.loadData(key, function(wrapper)
	{		
		var timeStamp = JSON.parse(wrapper)['timeStamp'];

		//the local version is more recent than the version we got from FB API.
		if (timeStamp < self.storage.timeStamp)
		{
			//push the local version to the FB server.
			self.storage.dataChanged = true;
		} processData(wrapper);
	}, onSuccess, onFail);
};
