//******************************************************

// *********************************
// CoolGames Builder JavaScript file
// *********************************

/**
 * Creates a new XMLHttpRequest and sends the message to the given endpoint.
 * For more information on HTTP requests, visit https://www.w3.org/Protocols/rfc2616/rfc2616-sec5.html
 * @param {String} endpoint the full endpoint for the call.
 * @param {String} methodType method for the request. Most common methodTypes are 'GET', 'POST', 'DELETE' and 'PUT'. Defaults to 'GET'.
 * @param {String} message the message to send. This will only work with certain method types. Defaults to null.
 * @param {Object} headers the headers consist of an array of objects. Each object has a 'key' and 'value' field. Defaults to [{key : "Content-Type", value : "application/json; charset=UTF-8"}].
 * @param {bool} async whether the call should be async. Defaults to true.
 * @param {bool} parse whether the data should be parsed using JSON once the response comes back. Defaults to true.
 * @param {requestCallback} resolve a callback that is called when the request resolves correctly. Contains the responseText as parameter. Parsed if parse is set to true.
 * @param {requestCallback} exception a callback that is called when the request resolves incorrectly. Contains the request as parameter.
 */
TGFEndpointDataHandler_HTTP_SendMessage = function(endpoint, methodType, message, headers, async, parse, resolve, exception)
{
	'use strict';
	
	var request = new XMLHttpRequest();

	methodType = methodType || 'GET';

	headers = headers instanceof Array ? headers : [{key : "Content-Type", value : "application/json; charset=UTF-8"}];

	message = message || null;

	if (async === undefined) async = true;

	if (parse === undefined) parse = true;

	request.open(methodType, endpoint, async);

	headers.forEach(function(element) 
	{
		request.setRequestHeader(element.key, element.value);
	}, this);

	request.onreadystatechange = function()
	{
		if (request.readyState === 4)
		{
			if (request.status === 200)
			{    
				if (resolve)
				{
					resolve(parse ? JSON.parse(request.responseText) : request.responseText);
				}            
			} else if (exception)
			{
				exception(request);
			}
		}
	};
	
	try
	{
		request.send(message);
	} catch (exc)
	{
		if (exception)
		{
			exception(request);
		}
	}
};

