// *********************************
// CoolGames Builder JavaScript file
// *********************************

tgfSettings.componentDefaults.multiFontLabel = {
    text: "",                                       //Example: <default>The same number can only occur </default><bold>once</bold><default> per </default><blue>block</blue><default>, </default><orange>column</orange><default> and </default><green>row</green><default>.</default>
    styles: {
        "default": {
            fontFace: undefined,
            fontSize: 16,
            fillColor: "#FF0000",
        }
	},
	font: f_tgf_text,	                                   
    dictionaryKey: "",
    align: "left",
    baseline: "top",
    fitToBox: true,	
    splitLines: false,
    surfaceMargin: 20,
    roundPosition: true,
    components: [],
    onClick: null
}

tgfComponents.MultiFontLabel = function(properties) {
    "use strict";
	this.name = "Label";

	// Initialize properties
	this.initialize(tgfSettings.componentDefaults.multiFontLabel);
	// Set user propertiesmultiFontLabel
	if (properties !== undefined) { this.setProperties(properties); }
};

// Inherit the label component
tgfComponents.inherit(tgfComponents.MultiFontLabel, tgfComponents.Label);

tgfComponents.MultiFontLabel.prototype.createSurface = function() {
	var HTMLParseElement = document.createElement( 'div' );
	HTMLParseElement.innerHTML = this.findText();

	var lines = [];
	lines.push([]);

	var oneLineWidth = 0;
	var oneLineHeight = 0;
	var lineHeight = 0
	var textHeight = 0;
	var lineWidth = 0;
	for (var i = 0; i < HTMLParseElement.children.length; i++) { 
		var text = HTMLParseElement.children[i].innerText;

		var words = text.split(/(\S+\s+)/).filter(function(n) {return n});

		for (var x = 0; x < words.length; x++) { 

			var word = words[x];
			var fontProperties = this.styles[HTMLParseElement.children[i].nodeName.toLowerCase()] || {};
			var font = new tbVectorFont();

			font.setProperties(this.font || {});
			font.setProperties(fontProperties);

			lineWidth += font.textWidth(word);

			var shouldSplitLines = this.splitLines && this.width > 0 && lineWidth > this.width;

			lineHeight = Math.max(lineHeight, font.textHeight(word) + font.spacing);

			if(shouldSplitLines) {
				lines[lines.length] = [];
				lineWidth = font.textWidth(word);
				textHeight+= lineHeight;
				lineHeight = 0;
			}

			oneLineWidth += font.textWidth(word);
			oneLineHeight = Math.max(oneLineHeight, font.textHeight(word) + font.spacing);

			lines[lines.length - 1].push({
				font: font,
				text: word
			});
		}
	}

	delete HTMLParseElement;

	textHeight+= lineHeight;

	if(this.fitToBox && (this.width > 0 || this.height > 0)) {
		lines = this._fitToBox(lines);
	}

	var width = this.width > 0 ? this.width : oneLineWidth;
	var height = this.height > 0 ? this.height : oneLineHeight;

	var getStartXPos = function() {
		switch (this.align) {
			case "left": return this.surfaceMargin;
			case "center": return this.surfaceMargin + width/2;
			case "right": return this.surfaceMargin + width;
			default: return this.surfaceMargin;
		}
	}.bind(this);

	var getStartYPos = function() {
		switch (this.baseline) {
			case "top": return this.surfaceMargin;
			case "middle": return this.surfaceMargin + height/2;
			case "bottom": return this.surfaceMargin + height;
			default: return this.surfaceMargin;
		}
	}.bind(this);

	this.textSurface = new tbSurface(width + 2 * this.surfaceMargin, height + 2 * this.surfaceMargin);

	this.textSurface.setTarget();

	var xPos = getStartXPos();
	var yPos = getStartYPos();
	for (var i = 0; i < lines.length; i++) { 

		var lineWidth = 0;
		for(var x = 0; x < lines[i].length; x++){
			lineWidth+= lines[i][x].font.textWidth(lines[i][x].text);
		}

		var lineHeight = 0;
		for(var x = 0; x < lines[i].length; x++){
			lineHeight = Math.max(lineHeight, lines[i][x].font.textHeight(lines[i][x].text) + lines[i][x].font.spacing);
		}

		var yy = this.baseline === "middle" ? yPos - (textHeight * 0.5) : yPos;
		yy = this.baseline === "bottom" ? yPos - textHeight : yy;

		for(var x = 0; x < lines[i].length; x++){

			var xx = this.align === "center" ? xPos - (lineWidth * 0.5) : xPos;
			xx = this.align === "right" ? xPos - lineWidth : xx;

			lines[i][x].font.drawSimple(lines[i][x].text, xx, yy);

			xPos+= lines[i][x].font.textWidth(lines[i][x].text);
		}

		xPos = getStartXPos();
		yPos+= lineHeight;
	}

	this.textSurface.resetTarget();
};

tgfComponents.MultiFontLabel.prototype.doDraw = function() {
	"use strict";
	// Determine the position of the text surface
	var xx = -this.textSurface.width/2, yy = -this.textSurface.height/2;
	if (this.roundPosition) { xx = Math.floor(xx); yy = Math.floor(yy); }
	switch (this.align) {
		case "left": xx = -this.surfaceMargin; break;
		case "right": xx = -this.textSurface.width + this.surfaceMargin; break;
	}
	switch (this.baseline) {
		case "top":  yy = -this.surfaceMargin; break;
		case "bottom": yy = -this.textSurface.height + this.surfaceMargin; break;
	}
	// Now draw it
	this.textSurface.drawSimple(xx, yy);
};

tgfComponents.MultiFontLabel.prototype._fitToBox = function(lines) {

	var fontFactor = 1;
	var fontFactorReduction = 0.05;

	var targetWidth = this.width > 0 ? this.width : Infinity;
	var targetHeight = this.height > 0 ? this.height : Infinity;

	var currentWidth = -1;
	var currentheight = -1;

	while((currentWidth === -1 && currentheight === -1) ||
		(currentWidth > targetWidth || 
		currentheight > targetHeight)) {

		fontFactor-= fontFactorReduction;

		currentWidth = 0;
		currentheight = 0;

		for (var i = 0; i < lines.length; i++) { 
			for(var x = 0; x < lines[i].length; x++) {
				lines[i][x].font.setFontSize(lines[i][x].font.getFontSize() * fontFactor);
			}

			var lineWidth = 0;
			var lineHeight = 0;

			for(var x = 0; x < lines[i].length; x++){
				lineWidth+= lines[i][x].font.textWidth(lines[i][x].text);
				lineHeight = Math.max(lineHeight, lines[i][x].font.textHeight(lines[i][x].text) + lines[i][x].font.spacing);
			}
			
			currentWidth = Math.max(currentWidth, lineWidth);
			currentheight+= lineHeight;
		}
	}

	return lines;
};
