//******************************************************
//*****    Script Resource: flowController
//******************************************************

// ***************************************
// flowController
//
//This object controls the flow for a standard game.
//
// Copyright 2015 Tingly Games B.V.
// Last Changed: 2-11-2015
// ***************************************

// Directives for jslint
/*global tbGame, tbGraphics, tbKeyCodes, tbLoader */
/*global tgfHooks, tgfFunctions, tgfDialogs, tgfComponents, tgfStatus, tgfDictionary, tgfGraphics, tgfAudio, tgfSettings, tgfAnalytics, tgfFramework */
/*global flowSettings, GameController, ThemeController, ClientController, playController */
/*global document */

// ***************************************
// Global variables created by the flow controller
// ***************************************

var gameController = null;                  // Object controlling the game
var themeController = null;                 // Object controlling the theme
var gamesBackendService = null;				// Service to connect to the backend
var profileManager = null;					// Holds information of the users (image, name);

var PlayerDataService = new LocalStoragePlayerDataService();
PlayerDataService.initialize();

// ***************************************
// The constructor for this flow token
// ***************************************

// The constructor for the FlowController game token. 
var FlowController = function() {
	"use strict";
	// Properties used by the engine
	this.depth = 0; 
	this.layer = 10000000;                              // Below everything else
	this.visible = false;
	this.active = true;
	this.adTimer = -1;
	// Own properties
	this.paused = 0;                                    // Whether the flow is paused (by a hook)
	this.currentAction = this.actionBeforeInitializing; // Current action to be performed
	this.afterGallery = undefined;
	// Add it to the game engine
	tbGame.addToken(this);
};

// Pause the flow
FlowController.prototype.pauseFlow = function() {
	"use strict";
	this.paused += 1;
};

// Resumes the flow
FlowController.prototype.resumeFlow = function() {
	"use strict";
	this.paused -= 1;
};

// Forces a resumes the flow ignoring the stacking
FlowController.prototype.resumeFlow = function() {
	"use strict";
	this.paused = 0;
};


// ***************************************
// Methods to be called by the play controller
// ***************************************

// Start playing the game (handles dialog, status, analytics and hooks)
FlowController.prototype.startPlay = function(action, dialogProperties, onContinue) {
	"use strict";
	var dialog, callback, res;
	// Pause the playing
	gameController.pausePlay();
	// Call the hook if any
	res = tgfHooks.execute("playStart");
	if (res !== undefined) { action = res; }
	// Create the callback function for after the dialog is shown
	callback = function (dialog) {
		var level = "Level" + tgfSettings.game.currentLevel;
		// Resume the playing
		gameController.resumePlay();
		// Update the status
		tgfStatus.startPlay(tgfSettings.game.currentMode, tgfSettings.game.currentLevel);
		// Add analytics
		//tgfAnalytics.reportEventExt(level, undefined, "Start");
		//tgfAnalytics.startTimedEventExt("durationWon", level, undefined, "WonDuration");
		//tgfAnalytics.startTimedEventExt("durationLost", level, undefined, "LostDuration");
		//tgfAnalytics.startTimedEventExt("stageCompleted", "Stage1", undefined, "StageDuration");
		// tgfAnalytics.reportEventExt("Start:",level, undefined, "progression");
		// Call the callback if any
		if (onContinue) { onContinue.call(playController); }
	};
	// If no dialog is shown, simply call the callback
	if (action !== "dialog") { callback(); return; }
	// Now show the dialog  
	if (tgfSettings.flow.startPlayDialog) {
		dialog = new tgfSettings.flow.startPlayDialog(dialogProperties);
	} else {
		dialog = new tgfDialogs.StartPlay(dialogProperties);
	}
	dialog.onHide = callback;
	dialog.show();
};

FlowController.prototype.startMultiplay = function(action, dialogProperties, onContinue) {
	"use strict";
	var dialog, callback, res;
	// Pause the playing
	gameController.pausePlay();
	// Call the hook if any
	res = tgfHooks.execute("playStart");
	if (res !== undefined) { action = res; }
	// Create the callback function for after the dialog is shown
	callback = function (dialog) {
		var level = "Level" + tgfSettings.game.currentLevel;
		// Resume the playing
		gameController.resumePlay();
		// Update the status
		tgfStatus.startPlay(tgfSettings.game.currentMode, tgfSettings.game.currentLevel);
		// Add analytics
		//tgfAnalytics.reportEventExt(level, undefined, "Start");
		//tgfAnalytics.startTimedEventExt("durationWon", level, undefined, "WonDuration");
		//tgfAnalytics.startTimedEventExt("durationLost", level, undefined, "LostDuration");
		//tgfAnalytics.startTimedEventExt("stageCompleted", "Stage1", undefined, "StageDuration");
		// tgfAnalytics.reportEventExt("Start:",level, undefined, "progression");
		// Call the callback if any
		if (onContinue) { onContinue.call(playController); }
	};
	// If no dialog is shown, simply call the callback
	if (action !== "dialog") { callback(); return; }
	// Now show the dialog  
	if (tgfSettings.flow.startMultiplayDialog) {
		dialog = new tgfSettings.flow.startMultiplayDialog(dialogProperties);
	} else {
		dialog = new tgfDialogs.MatchMaking(dialogProperties);
	}
	dialog.onHide = callback;
	dialog.show();

	return dialog;
};


// End a play by winning or loosing (determined by won argument)
FlowController.prototype.endPlay = function(won, score, time, stars, moves, action, dialogProperties, onContinue) {
	"use strict";
	var self = this, dialog, callback, res;
	// Pause the playing
	gameController.pausePlay();
	// Call the hook if any
	if (won) {
		res = tgfHooks.execute("playWon", score, time, stars, moves);
	} else {
		res = tgfHooks.execute("playLost");
	}
	if (res !== undefined) { action = res; }
	// Update the status
	if (won) {
		tgfStatus.endPlayWon(score, time, stars, moves);
	} else {
		tgfStatus.endPlayLost();
	}
	// Add the analytics
	if (won) {
		//tgfAnalytics.reportEventExt("Level" + tgfSettings.game.currentLevel, undefined, "Won");
		//tgfAnalytics.reportEventExt("Level" + tgfSettings.game.currentLevel, undefined, "Score", score);
		//tgfAnalytics.endTimedEvent("durationWon");
		//tgfAnalytics.cancelTimedEvent("durationLost");
		if(tgfHooks.playLost && score){
			tgfHooks.playLost(score);
		}
		// tgfAnalytics.reportEventExt("Complete:",tgfSettings.game.currentLevel, score, "progression");
	} else {
		//tgfAnalytics.reportEventExt("Level" + tgfSettings.game.currentLevel, undefined, "Lost");
		//tgfAnalytics.endTimedEvent("durationLost");
		//tgfAnalytics.cancelTimedEvent("durationWon");
		if(tgfHooks.playLost && score){
			tgfHooks.playLost(score);
		}
		// tgfAnalytics.reportEventExt("Fail:",tgfSettings.game.currentLevel, 0, "progression");
	}
	// Create the callback
	callback = function(dialog) { 
			// Resume the game
			gameController.resumePlay();
			// Handle the case where the play want to continue
			if (onContinue) { 
				onContinue.call(playController, self.afterPlay);
				return;
			}
			// Stop the playing
			if (self.afterPlay !== "continue") { gameController.stopPlay(); }
			// Take the correct action
			switch (self.afterPlay) {
				case "title": 
					self.currentAction = self.actionShowTitleScreen; 
					break;
				case "level": 
					self.currentAction = self.actionShowLevelScreen;
					//if(AudioController){ AudioController.playMapMusic(); }
					break;
				case "restart": 
					self.currentAction = self.actionStartPlay; 
					break;
				case "next": 
					if (tgfSettings.game.currentLevel < tgfSettings.game.levelCount) {
						tgfSettings.game.currentLevel += 1;
						self.currentAction = self.actionStartPlay;
					} else {
						self.currentAction = self.actionShowCompletionScreen;   
					}
					break;
				case "continue": break;
				default: self.currentAction = self.actionShowTitleScreen;
			}
			gameController.stopPlay();
			// Call the play end hook
			tgfHooks.execute("playEnd", false);
		};
	// If no dialog is shown, simply call the callback
	if (action !== "dialog") { this.afterPlay = action; callback(); return; }
	// Otherwise, create the dialog and show it
	if (won) {
		if (tgfSettings.flow.endPlayWonDialog) {
			dialog = new tgfSettings.flow.endPlayWonDialog(dialogProperties);
		} else {
			dialog = new tgfDialogs.EndPlayWon(dialogProperties);
		}
	} else {
		if (tgfSettings.flow.endPlayLostDialog) {
			dialog = new tgfSettings.flow.endPlayLostDialog(dialogProperties);
		} else {
			dialog = new tgfDialogs.EndPlayLost(dialogProperties);
		}
	}
	dialog.onClick = function(dialog, buttonId) { 
		dialog.disappear();
		self.afterPlay = buttonId;
	};
	
	if(this.adTimer < 0 && tgfSettings.flow.showMidroll){       
		dialog.onHide = function(){ gameController.stopPlay();
			self.currentAction = self.actionShowMidroll(callback); };
	} else {
		dialog.onHide = callback;
	}
	dialog.show();  
};

// End a play by winning
FlowController.prototype.endPlayWon = function(score, time, stars, moves, action, dialogProperties, onContinue) {
	"use strict";
	this.endPlay(true, score, time, stars, moves, action, dialogProperties, onContinue);
};

// End a play by losing
FlowController.prototype.endPlayLost = function(action, dialogProperties, onContinue) {
	"use strict";
	this.endPlay(false, undefined, undefined, undefined, undefined, action, dialogProperties, onContinue);
};

// A stage has been completed
FlowController.prototype.stageCompleted = function(stage, score, time, stars, moves, action, dialogProperties, onContinue) {
	"use strict";
	var dialog, callback, res;
	// Pause the playing
	gameController.pausePlay();
	// Call the hook if any
	res = tgfHooks.execute("stageCompleted", stage, score, time, stars, moves);
	if (res !== undefined) { action = res; }
	// Add the analytics
	//tgfAnalytics.reportEventExt("Stage" + stage, undefined, "Completed");
	//tgfAnalytics.endTimedEvent("stageCompleted");
	//tgfAnalytics.startTimedEventExt("stageCompleted", "Stage" + (stage+1), undefined, "StageDuration");
	// tgfAnalytics.reportEventExt("StageComplete:",stage, score, "design");
	// Create the callback function for after the dialog is shown
	callback = function (dialog) {
		// Resume the playing
		gameController.resumePlay();
		// Call the callback if any
		if (onContinue) { onContinue.call(playController); }
	};
	// If no dialog is shown, simply call the callback
	if (action !== "dialog") { callback(); return; }
	// Now show the dialog
	if (tgfSettings.flow.stageCompletedDialog) {
		dialog = new tgfSettings.flow.stageCompletedDialog(dialogProperties);
	} else {
		dialog = new tgfDialogs.StageCompleted(dialogProperties);
	}
	dialog.onHide = callback;
	dialog.show();
};

// Shows the in-game tutorial
FlowController.prototype.showTutorial = function(dialogProperties, onContinue) {
	"use strict";
	var dialog, callback;
	// Pause the playing
	gameController.pausePlay();
	// Create the callback function for after the dialog is shown
	callback = function (dialog) {
		// Resume the playing
		gameController.resumePlay();
		// Call the callback if any
		if (onContinue) { onContinue.call(playController); }
	};
	// Now show the dialog
	if (tgfSettings.flow.gameTutorialDialog) {
		dialog = new tgfSettings.flow.gameTutorialDialog(dialogProperties);
	} else {
		dialog = new tgfDialogs.GameTutorial(dialogProperties);
	}
	dialog.onHide = callback;
	dialog.show();
};

// Shows the in-game options dialog
FlowController.prototype.showOptions = function(dialogProperties, onContinue) {
	"use strict";
	var dialog, callback;
	// Pause the playing
	gameController.pausePlay();
	// Create the callback function for after the dialog is shown
	callback = function (dialog) {
		// Resume the playing
		gameController.resumePlay();
		// Call the continue method if any
		if (onContinue) { onContinue.call(playController); }
	};
	// Now show the dialog
	if (tgfSettings.flow.gameOptionsDialog) {
		dialog = new tgfSettings.flow.gameOptionsDialog(dialogProperties);
	} else {
		dialog = new tgfDialogs.GameOptions(dialogProperties);
	}
	dialog.onHide = callback;
	dialog.show();
};


// ***************************************
// Handle the flow. This consists of a number of
// actions. The current actions is called in the
// handleStep method. Some actions though are
// single actions or they wait for a dialog to
// finish, which then sets the next action
// ***************************************

// This action is done before initialization happens
FlowController.prototype.actionBeforeInitializing = function() {
	"use strict";
	var siteLocks, timeLock;
	// Initialize the flow settings
	tgfSettings.mergeSettings(flowSettings());
	// Create the game and theme controllers. These will merge their own settings in.
	gameController = new GameController();
	themeController = new ThemeController();

	//var _gameSparks = new window["GameSparks"]();
	//gamesBackendService = new GameSparksBackendService(_gameSparks, tgfSettings.gameSparks.appKey, tgfSettings.gameSparks.appSecret);
	// gamesBackendService.setDebugMode(true);
	// Initialize the hooks and deal with client settings
	tgfHooks.initialize();
	if (tgfSettings.client.analyticsTracking !== undefined) { tgfSettings.framework.initAnalytics = tgfSettings.client.analyticsTracking; }
	if (tgfSettings.client.initialLanguage !== undefined) { tgfSettings.dictionary.initialLanguage = tgfSettings.client.initialLanguage; }
	if (tgfSettings.client.availableLanguages !== undefined) { tgfSettings.dictionary.languages = tgfSettings.client.availableLanguages; }
	if (tgfSettings.client.splashScreenImage !== undefined) { tgfSettings.splashScreenDialogProperties.image = tgfSettings.client.splashScreenImage; }
	if (tgfSettings.client.splashScreenColor !== undefined) { tgfSettings.splashScreenDialogProperties.color = tgfSettings.client.splashScreenColor; }
	if (tgfSettings.client.splashScreenDuration !== undefined) { 
		tgfSettings.splashScreenDialogProperties.duration = tgfSettings.client.splashScreenDuration;
		tgfSettings.flow.showSplashScreenDialog = true;
	}
 
	if (tgfSettings.game.documentTitle) { document.title = tgfSettings.game.documentTitle; }
	// Continue to the next action FB instant style :)
	tgfHooks.execute("toggleAdBanner");
	this.currentAction = this.actionInitializing;
};

// This action is done once in the first step only to initialize stuff
FlowController.prototype.actionInitializing = function() {
	"use strict";
	// Initialize the framework
	tgfFramework.initialize(tgfSettings.framework);
	
	tgfGraphics.setBackgroundColor("black");
	//tgfGraphics.setBackgroundImage(window.location.href + "s_background.png");
	
	tgfAds.initialize(tgfSettings.tgfAdsProperties);
	
	//FIREBASE INIT TEST
	tgfFirebase.initialize(tgfSettings.tgfFirebaseProperties);
	
	// Continue to the next action 
	this.currentAction = this.actionWaitForInitializationToFinish;
};

// This action is performed while waiting for the initialization to finish
FlowController.prototype.actionWaitForInitializationToFinish = function() {
	"use strict";
	if (!tgfFramework.initComplete) { return; }         // Wait until the framework is completely loaded
	this.canvas = tgfGraphics.mainCanvas;               // Can only be done now that initialization is ready
	this.visible = true;

	this.currentAction = this.actionShowSplashScreen;
};

FlowController.prototype.actionInitializeAnalytics = function() {
	"use strict";
	var _version = gameSettings().game.version
};

// This action shows the splash screen, if any
FlowController.prototype.actionShowSplashScreen = function() {
	"use strict";
	var self = this;
	if (tgfSettings.flow.showSplashScreenDialog) {
		if (tgfSettings.flow.splashScreenDialog) {
			this.splashScreenDialog = new tgfSettings.flow.splashScreenDialog();
		} else {
			this.splashScreenDialog = new tgfDialogs.SplashScreen();
		}
		this.splashScreenDialog.onHide = function(dialog) { self.currentAction = self.actionHideSplashScreen; };
		this.splashScreenDialog.show();
		this.currentAction = undefined;
	} else {
		this.currentAction = this.actionStartLoadingResources;
	}
};

// Hide the splash screen
FlowController.prototype.actionHideSplashScreen = function() {
	"use strict";
	this.splashScreenDialog.free();
	this.splashScreenDialog = undefined;
	this.currentAction = this.actionStartLoadingResources;
};

// TODO: Deal with advertisements

// Start the loading of the resources, showing the load dialog when required
FlowController.prototype.actionStartLoadingResources = function() {
	"use strict";
	var self = this;

	// Start the actual loading
	tgfFunctions.loadStart( {
		moments: tgfSettings.flow.loadMoments,
		required: tgfSettings.flow.loadRequired,
		minTime: tgfSettings.flow.loadMinTime,
		maxTime: tgfSettings.flow.loadMaxTime       
	} );
	// Show the load screen dialog if required
	if (tgfSettings.flow.showLoadScreenDialog) {
		if (tgfSettings.flow.loadScreenDialog) {
			this.loadScreenDialog = new tgfSettings.flow.loadScreenDialog();
		} else {
			this.loadScreenDialog = new tgfDialogs.LoadScreen();
		}
		this.loadScreenDialog.progressFunction = tgfFunctions.loadPercentage;
		this.loadScreenDialog.onHide = function(dialog) { self.loadScreenDialog = undefined; };
		this.loadScreenDialog.show();
	} else {
		this.loadScreenDialog = undefined;
	}
	this.currentAction = this.actionWaitForLoadingToFinish;
};

FlowController.prototype.loadPlayerImage = function(imageUrl){
	"use strict"
	var self = this;
	var playerImage = new Image();

	playerImage.crossOrigin = 'anonymous';
	playerImage.src = imageUrl;

	return new Promise(function(resolve){
		playerImage.onload = function() {
			var image = tbImageFromImage("playerImage", playerImage, playerImage["width"], playerImage["height"], 0, 0);
			resolve(image);
			//console.log("Image created");
		};
	})
	
}

// This action is performed while waiting for the loading of the resources when there is no loading dialog
FlowController.prototype.actionWaitForLoadingToFinish = function() {
	"use strict";
	var self = this;
	// tgfHooks.execute("loadingProgress", tgfFunctions.loadPercentage());
	// Check whether the resources are loaded
	// if (!tgfFunctions.loadComplete()) { return; }
	// // Check whether the load screen dialog is gone
	if (this.loadScreenDialog) { return; }      
	// Start the title screen

	// tgfHooks.setStartCallback(function(){ 
		self.firstTimeMitigation = true; 
	// }); 

	tgfHooks.execute("afterLoading");
	 
	this.currentAction = this.waitForPromise;
};

FlowController.prototype.waitForPromise = function(){ 
	"use strict"; 
	if(this.firstTimeMitigation){
	  this.currentAction = this.actionAfterLoading; 
	} 
}; 

// This action is performed after the loading is completed (hence, only once)
FlowController.prototype.actionAfterLoading = function() {
	"use strict";
	var music;

	// Apply a hack to clear browser back buffer on Android stock browser
	// at this moment again because too early is not effective
	tgfGraphics.performBufferClearHack();
	// Play the background music
	if (tgfSettings.flow.titleScreenMusic) {
	   music = tgfAudio.play(tgfSettings.flow.titleScreenMusic);
	   tgfAudio.setLooping(music, true);
	}
	
	// Now go to the title screen
	//this.currentAction = this.actionShowTitleScreen;
	//Go to Ad Dialog
	this.currentAction = this.actionStartAd;
};

FlowController.prototype.actionStartAd = function() {
	"use strict";
	var self = this;
	this.currentAction = self.actionShowFacebookLogin;
};

FlowController.prototype.actionFinishAd = function() {
	"use strict";
	this.adDialog.free();
	this.adDialog = undefined;
	this.currentAction = this.actionShowTitleScreen;
};

FlowController.prototype.actionShowMidroll = function(callback){
	"use strict";
	var self = this;
	
	if(tgfSettings.flow.showMidroll){
		if(tgfSettings.flow.midrollDialog){
			this.midDialog = new tgfSettings.flow.midrollDialog(tgfSettings.adStageDialogProperties);
		} else {
			this.midDialog = new tgfDialogs.AdDialogStage(tgfSettings.adStageDialogProperties);
		}
		
		this.midDialog.onHide = callback;
		
		this.midDialog.show();
		
		this.currentAction = undefined;
	}
};

FlowController.prototype.actionShowFacebookLogin = function(){
	"use strict";
	var self = this;
	
	if(tgfSettings.flow.showFacebookLogin){
		if(tgfSettings.flow.facebookLoginDialog){
			this.loginDialog = new tgfSettings.flow.facebookLoginDialog();
		} else {
			this.loginDialog = new tgfDialogs.LoginScreen();
		}
		
		this.loginDialog.onHide = function(){
			self.currentAction = self.actionHideFacebookLogin;
		};
		
		this.loginDialog.show();
		this.currentAction = undefined;
	} else {
		this.currentAction = this.actionShowTitleScreen;
	}
};

FlowController.prototype.actionHideFacebookLogin = function(){
	"use strict";
	this.loginDialog.free();
	this.loginDialog = undefined;
	this.currentAction = this.actionShowTitleScreen;
};

// Show the title screen dialog
FlowController.prototype.actionShowTitleScreen = function() {
	"use strict";
	var self = this;
	// Show the title screen if required
	if (tgfSettings.flow.showTitleScreenDialog) {
		tgfHooks.execute("beforeTitleScreen");
		if (tgfSettings.flow.titleScreenDialog) {
			this.titleScreenDialog = new tgfSettings.flow.titleScreenDialog();
		} else {
			this.titleScreenDialog = new tgfDialogs.TitleScreen();
		}
		this.titleScreenDialog.onHide = function(dialog) { self.currentAction = self.actionHideTitleScreen; };
		this.titleScreenDialog.onLanguage = function(dialog) { self.currentAction = self.actionShowLanguageMenu; };
		this.titleScreenDialog.onPlay = function(state){ self._startMultiplay = state; };
		this.titleScreenDialog.onMultiplay = function(dialog) {
			self._startMultiplay = "multiplay";
			self.currentAction = self.actionMatchMake;
		};
		this.titleScreenDialog.onMenu = function(dialog) {
//          dialog.hide();
			self.currentAction = self.actionShowTitleMenu};
		this.titleScreenDialog.onGallery = function(state){
			self.afterGallery = "title";
			self._startMultiplay = state;
			self.titleScreenDialog.hide();
		};
		this.titleScreenDialog.show();
		this.currentAction = undefined;
	} else {
		this.currentAction = this.actionShowLevelScreen;
	}
};

// Hide the title screen dialog
FlowController.prototype.actionHideTitleScreen = function() {
	"use strict";
	this.titleScreenDialog.free();
	this.titleScreenDialog = undefined;
	if(this._startMultiplay === "multiplay"){
		this.currentAction = undefined;
		gameController.startMultiPlay();
	}else if(this._startMultiplay === "play"){
		this.currentAction = this.actionShowLevelScreen;
	} else if(this._startMultiplay === "gallery") {
		this.currentAction = this.actionShowGallery;
	}
};

FlowController.prototype.actionShowGallery = function(){
	"use strict";
	var self = this;

	this.galleryDialogScreen = new tgfDialogs.GalleryDialog();

	this.galleryDialogScreen.onHide = function(dialog){
		self.currentAction = self.actionHideGallery;
	};

	this.galleryDialogScreen.show();

	this.currentAction = undefined;
};

FlowController.prototype.actionHideGallery = function(){
	"use strict";

	this.galleryDialogScreen.doFree();
	this.galleryDialogScreen = undefined;

	if(this.afterGallery === "title"){
		this.currentAction = this.actionShowTitleScreen;
	} else if(this.afterGallery === "gallery"){
		this.currentAction = undefined;
	}else{
		this.currentAction = undefined;
	}
	this.afterGallery = undefined;
};

FlowController.prototype.actionMatchMake = function(){
	"use strict";
	var self = this;
	if(tgfSettings.flow.matchMakingDialog){
		this.matchmakingDialog = new tgfSettings.flow.matchMakingDialog(tgfSettings.matchMakingProperies);
	}else{
		this.matchmakingDialog = new tgfDialogs.MatchMaking(tgfSettings.matchMakingProperies);
	}
	
	this.matchmakingDialog.onMatchMade = function(properties){
		gameController.startMultiPlay(properties); 
		self.currentAction =  self.actionHideTitleScreen;
		self.matchmakingDialog.doFree();
		//self.matchmakingDialog.undefined;
	};
	this.matchmakingDialog.onHide = function(dialog) {
		if (dialog.canceled) {
			self.titleScreenDialog.activate();
			self.matchmakingDialog.doFree();
			//self.matchmakingDialog.undefined;
		} else {
			gameController.initMultiplay();
		}
	};
	this.matchmakingDialog.show();
	this.currentAction = undefined;
};

FlowController.prototype.actionShowLanguageMenu = function(){
	"use strict";
	var self = this;
	
	if(tgfSettings.flow.showLanguageMenuDialog){
		if(tgfSettings.flow.titleLanguageDialog){
			this.titleLanguageDialog = new tgfSettings.flow.titleLanguageDialog();
		} else {
			this.titleLanguageDialog = new tgfDialog.LanguageScreen();
		}
		this.titleLanguageDialog.onClick = function(dialog, id) { self.titleLanguageDialog.changeLanguage(id);};
		this.titleLanguageDialog.onHide = function(dialog) { self.currentAction = self.actionHideLanguageMenu();};
		this.titleScreenDialog.deactivate();
		this.titleLanguageDialog.show();
		this.currentAction = undefined;
	}
};

FlowController.prototype.actionHideLanguageMenu = function(){
	"use strict";
//  this.titleLanguageDialog.free(); //Has no Free function / should fix?
	this.titleScreenDialog.activate();
	this.titleLanguageDialog = undefined;
	this.currentAction = undefined;
};


// Show the title screen options menu dialog
FlowController.prototype.actionShowTitleMenu = function() {
	"use strict";
	var self = this;
	if (tgfSettings.flow.showTitleMenuDialog) {
		//this.titleMenuDialog = new tgfDialogs.ButtonBox(tgfSettings.flow.titleMenuProperties);
		if(tgfSettings.flow.titleMenuDialog){
			this.titleMenuDialog = new tgfSettings.flow.titleMenuDialog(tgfSettings.titleOptionsDialogProperties);
		}else{
			this.titleMenuDialog = new tgfDialogs.OptionScreen(tgfSettings.titleOptionsDialogProperties);
		}
		
		this.titleMenuDialog.onTutorial = function(dialog) { self.currentAction = self.actionShowTutorialScreen; };
		this.titleMenuDialog.onHide = function(dialog) { self.currentAction = self.actionHideTitleMenu; };
		this.titleMenuDialog.onAbout = function(dialog) { self.currentAction = self.actionShowAboutScreen; };
		// Show it, deactivating the title screen
		this.titleScreenDialog.deactivate();
		this.titleMenuDialog.show();
		this.currentAction = undefined;
	}
};

// Hide the title screen options menu dialog
FlowController.prototype.actionHideTitleMenu = function() {
	"use strict";
	this.titleMenuDialog.free();
	
	this.titleMenuDialog = undefined;
	
	if(this.optionsAboutDialog !== undefined) { this.currentAction = this.actionHideAboutScreen; }
	this.titleScreenDialog.activate();
	this.currentAction = undefined;
};

FlowController.prototype.actionShowGameMenu = function(_base){
	"use strict";
	var self = this, moregames;
	if (tgfSettings.flow.showGameMenuDialog) {
		moregames = tgfHooks.execute("getMoreGamesFunction");
		if(tgfSettings.flow.gameOptionsDialog){
			this.gameOptionsDialog = new tgfSettings.flow.gameOptionsDialog(tgfSettings.gameOptionsDialogProperties);
		}else{
			this.gameOptionsDialog = new tgfDialogs.OptionScreen(tgfSettings.gameOptionsDialogProperties);
		} 
		if(moregames){
			this.gameOptionsDialog.onMoreGames = moregames;
		}
		this.gameOptionsDialog.onTutorial = function(dialog) { self.currentAction = self.actionShowTutorialScreen; };
		this.gameOptionsDialog.onHide = function(dialog) { self.currentAction = self.actionHideGameMenu; };
		this.gameOptionsDialog.onExit = function(dialog) { 
											dialog.base.hide();
											self.actionHideGameMenu();
											self.currentAction = self.actionShowTitleScreen;
										};
		this.gameOptionsDialog.base = _base;
		// Show it, deactivating the title screen
		if(this.levelScreenDialog !== undefined) {this.levelScreenDialog.deactivate();}
		this.gameOptionsDialog.show();
		this.currentAction = undefined;
	}
};

FlowController.prototype.actionHideGameMenu = function() {
	"use strict";
	this.gameOptionsDialog.free();
	this.gameOptionsDialog = undefined;
	if(this.levelScreenDialog !== undefined) {this.levelScreenDialog.activate();}
	this.currentAction = undefined;
};

// Show the level select screen, if any
FlowController.prototype.actionShowTutorialScreen = function() {
	"use strict";
	var self = this;
	
	if(tgfSettings.flow.showTutorialScreen){
		if(tgfSettings.flow.gameTutorialDialog){            
			this.tutorialScreenDialog = new tgfSettings.flow.gameTutorialDialog(tgfSettings.optionsTutorialDialogProperties);
		} else {
			this.tutorialScreenDialog = new tgfDialogs.Tutorial(tgfSettings.optionsTutorialDialogProperties);
		}
	
		this.tutorialScreenDialog.onHide = function(dialog) { self.currentAction = self.actionHideTutorialScreen; };
		// Show it, deactivating the menu screen
		if(this.titleMenuDialog){
			this.titleMenuDialog.deactivate();
		} 
		this.tutorialScreenDialog.show();
		this.currentAction = undefined;
	}
};

// Hide the tutorial screen dialog
FlowController.prototype.actionHideTutorialScreen = function() {
	"use strict";
	this.tutorialScreenDialog.free();
	this.tutorialScreenDialog = undefined;
	if(this.titleMenuDialog){       
		this.titleMenuDialog.activate();
	} else if(this.inGameOptionsDialog) {
		this.inGameOptionsDialog.activate();
		this.inGameOptionsDialog.switchText();
	}
	this.currentAction = undefined;
};

FlowController.prototype.actionShowAboutScreen = function() {
	"use strict";
	var self = this;
	if(tgfSettings.flow.showAboutScreenDialog){
		if(tgfSettings.flow.optionsAboutDialog){
			this.optionsAboutDialog = new tgfSettings.flow.optionsAboutDialog();
		} else {
			this.optionsAboutDialog = new tgfDialogs.AboutScreen();
		}
	
		this.optionsAboutDialog.onHide = function(dialog){ self.currentAction = self.actionHideAboutScreen; };
		
		if(this.titleMenuDialog !== undefined){ this.titleMenuDialog.deactivate(); }
		else if(this.gameOptionsDialog !== undefined){ this.gameOptionsDialog.deactivate(); }
		
		this.optionsAboutDialog.show();
		this.currentAction = undefined;
	}
};

FlowController.prototype.actionHideAboutScreen = function(){
	"use strict";
	
	if(this.titleMenuDialog !== undefined){ this.titleMenuDialog.activate(); }
	else if(this.gameOptionsDialog !== undefined){ this.gameOptionsDialog.activate(); }
	this.currentAction = undefined;
};

FlowController.prototype.showImmidiateDialog = function(dialog){
	"use strict";
	switch(dialog){
	  case "title":
		 gameController.stopPlay();
		  this.afterGallery = dialog;
		 this.currentAction = this.actionShowTitleScreen; 
		break;
	  case "level":
		 gameController.stopPlay();
		 this.currentAction = this.actionShowLevelScreen;
		 //if(AudioController){ AudioController.playMapMusic(); }
		break;
	  case "gallery":
		  gameController.stopPlay();
		  this.afterGallery = dialog;
		  this.currentAction = this.actionShowGallery();
		break;
	}
};

// Show the level selection screen
FlowController.prototype.actionShowLevelScreen = function() {
	"use strict";
	var self = this;
	tgfHooks.execute("beforeLevelScreen");
	if (tgfSettings.flow.showLevelScreenDialog) {
		if (tgfSettings.flow.levelScreenDialog) {
			this.levelScreenDialog = new tgfSettings.flow.levelScreenDialog();
		} else {
			this.levelScreenDialog = new tgfDialogs.LevelScreen();
		}
		
		this.levelScreenDialog.onHide = function(dialog) { self.currentAction = self.actionHideLevelScreen; };
		this.levelScreenDialog.onClick = function(dialog, level) { 
			tgfSettings.levelSelectionProperties.levelPressed = level;
			self.currentAction = self.actionShowLevelSelectionScreen; 
		};
		this.levelScreenDialog.onOptions = function(dialog) {self.currentAction = self.actionShowGameMenu(self.levelScreenDialog);};
		
		this.levelScreenDialog.show();
		this.currentAction = undefined;
	} else {
		tgfSettings.game.currentLevel = 1;
		this.currentAction = this.actionStartPlay;
	}
};

// Hide the level selection screen dialog
FlowController.prototype.actionHideLevelScreen = function() {
	"use strict";
	// TODO: Deal with the actual setting of the level
//  this.levelScreenDialog.free();
	this.levelScreenDialog = undefined;
//  this.currentAction = this.actionStartPlay;
};

FlowController.prototype.actionShowLevelSelectionScreen = function(level){
	"use strict";
	var self = this;
	
	if(tgfSettings.flow.showLevelSelectionDialog){
		if(tgfSettings.flow.levelSelectionDialog){
			this.levelSelectionDialog = new tgfSettings.flow.levelSelectionDialog;
		} else {
			this.levelSelectionDialog = new tgfDialog.LevelPopUp();
		}
		this.levelSelectionDialog.onHide = function(dialog){ self.currentAction = self.actionHideLevelSelectionScreen; };
		this.levelSelectionDialog.onPlay = function(dialog, level){ 
			tgfSettings.game.currentLevel = level;
			self.currentAction = self.actionStartPlay;
		};
		this.levelSelectionDialog.show();
		this.levelScreenDialog.deactivate();
		this.currentAction = undefined;
	} else {
		tgfSettings.game.currentLevel = level;
		this.currentAction = this.actionStartPlay;
	}
};

FlowController.prototype.actionHideLevelSelectionScreen = function(){
	"use strict";
	this.levelScreenDialog.activate();
	this.levelSelectionDialog.free();
	this.levelSelectionDialog = undefined;
	this.currentAction = undefined;
};

FlowController.prototype.actionShowInGameOptions = function(_ui, _showId){
	"use strict";
	var self = this;
	var showId = "";
	
	if(tgfSettings.flow.showInGameMenuDialog){
		
		if(tgfSettings.flow.inGameOptionsDialog){
			this.inGameOptionsDialog = new tgfSettings.flow.inGameOptionsDialog(tgfSettings.inGameOptionsDialogProperties);
			if(_showId){
				this.inGameOptionsDialog.quitYesButtonId = _showId;
			}
		} else {
			this.inGameOptionsDialog = new tgfDialogs.OptionScreen(tgfSettings.inGameOptionsDialogProperties);
			if(_showId){
				this.inGameOptionsDialog.quitYesButtonId = _showId;
			}
		}
		this.inGameOptionsDialog.onHide = function(dialog){ 
			switch(showId) {
				case "title":
					self.currentAction = self.actionShowTitleScreen;
					break;
				case "level":
					self.currentAction = self.actionShowLevelScreen;
					break;
				default:
					gameController.resumeUI(_ui);
					gameController.resumePlay();
			}
			self.inGameOptionsDialog = undefined;
		};
		this.inGameOptionsDialog.onShow = function(dialog){ 
			gameController.pauseUI(_ui);
			gameController.pausePlay(); };
		this.inGameOptionsDialog.onTutorial = function(dialog) { 
			dialog.deactivate();
			self.currentAction = self.actionShowTutorialScreen; };
		this.inGameOptionsDialog.onQuitYes = function(dialog, show){
			showId = show;
			gameController.stopPlay();
		};
		this.inGameOptionsDialog.show();
		this.currentAction = undefined;
	}
};

FlowController.prototype.actionHideInGameOptions = function(){
	"use strict";
};

// Start playing the games
FlowController.prototype.actionStartPlay = function() {
	"use strict";
	// Pass control over to the game controller
	gameController.startPlay();
	if(this.levelScreenDialog !== undefined){ 
		this.levelScreenDialog.hide();
		this.currentAction = this.actionHideLevelScreen; 
	}
	this.currentAction = undefined;
	
};

// This action shows the completion screen, if any
FlowController.prototype.actionShowCompletionScreen = function() {
	"use strict";
	var self = this;
	if (tgfSettings.flow.showCompletionScreenDialog) {
		if (tgfSettings.flow.completionScreenDialog) {
			this.completionScreenDialog = new tgfSettings.flow.completionScreenDialog();
		} else {
			this.completionScreenDialog = new tgfDialogs.CompletionScreen();
		}
		this.completionScreenDialog.onHide = function(dialog) { self.currentAction = self.actionHideCompletionScreen; };
		this.completionScreenDialog.show();
		this.currentAction = undefined;
	} else {
		this.currentAction = this.actionShowTitleScreen;
	}
};

// Hide the completion screen
FlowController.prototype.actionHideCompletionScreen = function() {
	"use strict";
	this.completionScreenDialog.free();
	this.completionScreenDialog = undefined;
	// Take the correct action
	switch (tgfSettings.flow.completionScreenAction) {
		case "title": this.currentAction = this.actionShowTitleScreen; break;
		case "level": this.currentAction = this.actionShowLevelScreen; break;
		case "restart": 
			tgfSettings.game.currentLevel = 1;
			this.currentAction = this.actionStartPlay; 
			break;
		default: this.currentAction = this.actionShowTitleScreen;
	}
};

// ***************************************
// Event handling methods
// ***************************************

FlowController.prototype.handleEndStep = function(timePassed) { 
	"use strict";
	// Check whether the flow is paused
	if (this.paused > 0) { return; }
	// Perform the current action
	if (this.currentAction) { this.currentAction(timePassed); }
	
	if(this.adTimer > -1){
		this.adTimer -= timePassed;
//      console.log(this.adTimer);
	}
};

FlowController.prototype.handleDraw = function() { 
	"use strict";
	// Clear the dynamic canvasses
	tgfGraphics.clearDynamicCanvasses();
};

