/////////////////////////////////////////////////////////////
// Snake
//
// This object contains all global functions and properties
//
// Copyright 2014 Tingly Games
// Last Changed: 30-05-2014
/////////////////////////////////////////////////////////////

var Snake = {

	// ****************************************
	// General properties
	// ****************************************
		
	gameModeInit : 0,
	gameModeStarted : 1,
	gameModePlaying : 2,
	gameModeReady : 3,
	gameModeExiting : 4,
	gameModeCollision : 5,
	gameModeFinished : 6,
	gameModeOver : 7,

	mode : 0,               // Current mode of the game
	controller : null,      // The level controller

	// ****************************************
	// Dealing with the field
	// ****************************************

	level : -1,             // The current level
	cellSize : 36,          // Size of the cells in pixels
	horNumber : 19,         // Horizontal number of cells (adding an empty ring)
	vertNumber : 19,        // Vertical number of cells (adding an empty ring)
	xOff : 0,               // Horizontal offset of the field
	yOff : 0,               // Vertical offset of the field
	layout : [],            // The layout of cells in the level
	holeToken : null,       // The token for the hole (for entry and exit)
	snakeToken : null,      // The token for the snake
	
	// Return the horizontal cell containing the x position
	hCell : function(xpos) {
		"use strict";
		return Math.floor((xpos-Snake.xOff) / Snake.cellSize) + 1;
	},

	// Return the vertical cell containing the y position
	vCell : function(ypos) {
		"use strict";
		return Math.floor((ypos-Snake.yOff) / Snake.cellSize) + 1;
	},

	// Return the x-position of the center of the cell
	xCell : function(xc) {
		"use strict";
		return Snake.xOff + Snake.cellSize*(xc-0.5);
	},

	// Return the y-position of the center of the cell
	yCell : function(yc) {
		"use strict";
		return Snake.yOff + Snake.cellSize*(yc-0.5);
	},

	// Return the contents (character of the given cell)
	cellContents : function(x, y) {
		"use strict";
		if (x < 0 || y < 0 || x >= Snake.horNumber || y >= Snake.vertNumber) { return ' '; }
		return Snake.layout[y][x];
	},

	// Copy part of the background
	_copyBackground : function(x, y, w, h) {
		"use strict";
		//TG.controller.drawInGameBackground(Snake.xOff + Snake.cellSize*x, Snake.yOff + Snake.cellSize*y, Snake.cellSize*w, Snake.cellSize*h);
		w = w || tgfGraphics.areaWidth;
		w = h || tgfGraphics.areaHeight;

		//s_background.drawCombinedPart(x, y, w, h, x, y, 1);
	},

	movementGrid : function(){
		"use strict";

		var grid = [];


		for(var x = 0; x < Snake.horNumber + 1; x++){
			grid.push([]);
			for(var y = 0; y < Snake.vertNumber + 1; y++){
				var pos = {x: 0, y: 0};
				pos.x = Snake.xCell(x);
				pos.y = Snake.yCell(y);

				grid[x].push(pos);
			}
		}

		return grid;
	},

	// Initializes the indicated level for the field 
	initLevel : function(level) {
		"use strict";
		var globalSettings = TG.settings.game.field,
			levelDescription = TG.settings.game.levels[level].layout,
			x, y, subImg;
		// Fill in the setting, adding an additional ring of empty cells
		Snake.cellSize = globalSettings.cellSize;
		Snake.horNumber = globalSettings.horNumber + 2;
		Snake.vertNumber = globalSettings.vertNumber + 2;
		Snake.xOff = (tgfGraphics.areaWidth-Snake.cellSize*(Snake.horNumber-2)) / 2 + TG.gameOffsetX;
		Snake.yOff = (tgfGraphics.areaHeight-Snake.cellSize*(Snake.vertNumber-2)) / 2 + TG.gameOffsetY;
		// Fill in the data for this level
		Snake.level = level;
		Snake.layout = [];
		for (y = 0; y < Snake.vertNumber; y += 1) {
			Snake.layout.push([]);
			for (x = 0; x < Snake.horNumber; x += 1) {
				Snake.layout[y].push('O');
			}
		}
		for (y = 1; y < Snake.vertNumber-1; y += 1) {
			for (x = 1; x < Snake.horNumber-1; x += 1) {
				Snake.layout[y][x] = levelDescription[y-1].charAt(x-1);
			}
		}
		// Create the layout
		//TG.functions.setCanvas(TG.gameBackgroundLayer);
		// Draw the field background
		//(Snake.horNumber*Snake.cellSize-s_field.width)/2
		//s_field.drawSimple(0, (Snake.horNumber*Snake.cellSize-s_field.width)/2 - Snake.cellSize + Snake.xOff,
		//                      (Snake.vertNumber*Snake.cellSize-s_field.height)/2 - Snake.cellSize + Snake.yOff);
		// Draw the real background where needed
		Snake._copyBackground(0, 0, 1, 0.5);
		for (y = 1; y < Snake.vertNumber-1; y += 1) {
			for (x = 1; x < Snake.horNumber-1; x += 1) {
				if (Snake.layout[y][x] === 'O') {
					Snake._copyBackground(x-1, y-1, 1, 1);
				} else if (Snake.layout[y][x] === 'X') {
					if (Snake.layout[y][x-1] === 'O') { Snake._copyBackground(x-1, y-1, 0.5, 1); }
					if (Snake.layout[y][x+1] === 'O') { Snake._copyBackground(x-0.5, y-1, 0.5, 1); }
					if (Snake.layout[y-1][x] === 'O') { Snake._copyBackground(x-1, y-1, 1, 0.5); }
					if (Snake.layout[y+1][x] === 'O') { Snake._copyBackground(x-1, y-0.5, 1, 0.5); }
					if (Snake.layout[y-1][x-1] === 'O') { Snake._copyBackground(x-1, y-1, 0.5, 0.5); }
					if (Snake.layout[y-1][x+1] === 'O') { Snake._copyBackground(x-0.5, y-1, 0.5, 0.5); }
					if (Snake.layout[y+1][x-1] === 'O') { Snake._copyBackground(x-1, y-0.5, 0.5, 0.5); }
					if (Snake.layout[y+1][x+1] === 'O') { Snake._copyBackground(x-0.5, y-0.5, 0.5, 0.5); }
				}
			}
		}
		// Draw the walls
		for (y = 1; y < Snake.vertNumber-1; y += 1) {
			for (x = 1; x < Snake.horNumber-1; x += 1) {
				if (Snake.layout[y][x] === 'X') {
					subImg = 0;
					if (Snake.layout[y][x+1] === 'X') { subImg += 1; }
					if (Snake.layout[y-1][x] === 'X') { subImg += 2; }
					if (Snake.layout[y][x-1] === 'X') { subImg += 4; }
					if (Snake.layout[y+1][x] === 'X') { subImg += 8; }
					s_wall.drawSimple(subImg, Snake.cellSize*(x-1) + Snake.xOff, Snake.cellSize*(y-1) + Snake.yOff);
				}
			}
		}

		Snake.moveGrid = Snake.movementGrid();

		// Further initialization
		Snake.initEggLocations();
		Snake.initItemLocations();
	},

	// Starts the field, creating the tokens
	startLevel : function() 
	{
		"use strict";
		var x, y;

	   // Create the tokens when required
		for (y = 1; y < Snake.vertNumber-1; y += 1) 
		{
			for (x = 1; x < Snake.horNumber-1; x += 1) 
			{
				if (Snake.layout[y][x] === 'S') 
				{
					// TODO: Make it work from the level editor again! -Nils
					var startPosition = {
						x: Snake.xCell(x),
						y: Snake.yCell(y)
					};

					Snake.snakeToken = new TokenSnake(startPosition.x, startPosition.y);
				}
				if (Snake.layout[y][x] === 'o') 
				{
					new AppleCollectible(
						Snake.xOff + Snake.cellSize*(x-0.5),
						Snake.yOff + Snake.cellSize*(y-0.5),
						this.onCollectibleEaten,
						this);
				}
				if (Snake.layout[y][x] === 'c') 
				{
					new TokenChicken(Snake.xOff + Snake.cellSize*(x-0.5), Snake.yOff + Snake.cellSize*(y-0.5));
				}
				if (Snake.layout[y][x] === '>') 
				{
					new TokenEnemy(Snake.xOff + Snake.cellSize*(x-0.5), Snake.yOff + Snake.cellSize*(y-0.5), 1);
				}
				if (Snake.layout[y][x] === '<') 
				{
					new TokenEnemy(Snake.xOff + Snake.cellSize*(x-0.5), Snake.yOff + Snake.cellSize*(y-0.5), -1);
				}
			}
		}
	},

	onCollectibleEaten : function(collectible)
	{
		Snake.snakeToken.addCollectible(collectible);
	},
	
	// ****************************************
	// Dealing with collisions
	// ****************************************

	// Returns whether a collision occurs with a wall at position (x,y) with the given margin
	checkCollision : function(x, y, margin) {
		"use strict";
		var xc = Snake.hCell(x), yc = Snake.vCell(y), i, j, dd;
		// Check the cell
		if (Snake.layout[yc][xc] === 'X') { return true; }

		if (Snake.layout[yc][xc] === 'W') { return true; }
		// Check the neighboring cells
		dd = Math.pow(margin + Snake.cellSize/2, 2);
		for (i = -1; i < 2; i += 1) {
			for (j = -1; j < 2; j += 1) {
				if (Snake.layout[yc+i][xc+j] === 'X' &&
					Math.pow(x - Snake.xCell(xc+j), 2) + Math.pow(y - Snake.yCell(yc+i), 2) < dd) {
					return true;
				}
				if (Snake.layout[yc+i][xc+j] === 'W' &&
					Math.pow(x - Snake.xCell(xc+j), 2) + Math.pow(y - Snake.yCell(yc+i), 2) < dd) {
					return true;
				}
			}
		}
		return false;
	},

	// ****************************************
	// Dealing with eggs, bonuses, and power-ups
	// ****************************************

	eggLocations : [],          // possible egg locations
	lastEggLocation : -1,       // last used egg location
	itemLocations : [],         // possible item locations
	lastItemLocation : -1,      // last used item location
	
	// Initializes the list of all possible locations for eggs or chicken
	initEggLocations : function() {
		"use strict";
		var x, y, n, i, j, temp;
		Snake.eggLocations = [];
		Snake.lastEggLocation = -1;
		// Find all locations
		for (y = 1; y < Snake.vertNumber-1; y += 1) {
			for (x = 1; x < Snake.horNumber-1; x += 1) {
				if (Snake.layout[y][x] === '.' || Snake.layout[y][x] === 'S') {
					Snake.eggLocations.push({ kind: "egg", x: Snake.xOff + Snake.cellSize*(x-0.5), y: Snake.yOff + Snake.cellSize*(y-0.5) });
				}
			}
		}
		// Put them in random order
		for (n = 0; n < 1000; n += 1) {
			i = defaultRandom.iRandom(Snake.eggLocations.length-1);
			j = defaultRandom.iRandom(Snake.eggLocations.length-1);
			temp = Snake.eggLocations[i];
			Snake.eggLocations[i] = Snake.eggLocations[j];
			Snake.eggLocations[j] = temp;
		}
	},

	// Returns a possible location for the egg
	getCollectibleLocation : function() 
	{
		return Snake.findCollectibleLocation(5);
	},

	findCollectibleLocation : function(minDist)
	{
		"use strict";
		var xx, yy, n, items, i, ok, tries;
		items = tbGame.findTokens("item");
		// Find a good location
		Snake.lastEggLocation	+= Math.floor(Math.random() * Snake.eggLocations.length * 0.5);
		tries = Snake.eggLocations.length;        // Avoid too many tries per step
		for (n = 0; n < tries; n += 1)
		{
			Snake.lastEggLocation += 1;
			Snake.lastEggLocation = Snake.lastEggLocation % Snake.eggLocations.length;

			xx = Snake.eggLocations[Snake.lastEggLocation].x;
			yy = Snake.eggLocations[Snake.lastEggLocation].y;
			ok = true;

			if (Math.pow(Snake.snakeToken.headX()-xx, 2) + Math.pow(Snake.snakeToken.headY()-yy, 2) < Math.pow(minDist * .5 * Snake.cellSize,2)) 
			{
				ok = false;
			}
			if (ok && Snake.snakeToken.checkCollision(xx, yy, Snake.cellSize * .5, false)) 
			{ 
				ok = false; 			
			}

			for (i = 0; i < items.length; i += 1)
		 	{				
				if (Math.abs(items[i].x-xx)< Snake.cellSize) 
				{
					ok = false; 
				}

				if (Math.abs(items[i].y-yy)< Snake.cellSize) 
				{
					ok = false; 
				}

				if (Math.pow(items[i].x-xx,2) + Math.pow(items[i].y-yy,2) < Math.pow(minDist * .5 * Snake.cellSize,2)) 
				{
					ok = false; 
				}
			}
			if (ok) 
			{ 
				return Snake.eggLocations[Snake.lastEggLocation];
			}
		}
		if (minDist === 0)
		{
			//there are absolutely no places left to spawn anything, so don't spawn anything.			
			return undefined;
		}
		return Snake.findCollectibleLocation(minDist - 1);
	},

	// Initializes the list of all possible locations for items
	initItemLocations : function() {
		"use strict";
		var x, y, n, i, j, temp;
		Snake.itemLocations = [];
		Snake.lastItemLocation = -1;
		// Find all locations
		for (y = 1; y < Snake.vertNumber-1; y += 1) {
			for (x = 1; x < Snake.horNumber-1; x += 1) {
				if (Snake.layout[y][x] === 'B') {
					Snake.itemLocations.push({ kind: "bonus", x: Snake.xOff + Snake.cellSize*(x-0.5), y: Snake.yOff + Snake.cellSize*(y-0.5) });
				}
				if (Snake.layout[y][x] === 'P') {
					Snake.itemLocations.push({ kind: "power", x: Snake.xOff + Snake.cellSize*(x-0.5), y: Snake.yOff + Snake.cellSize*(y-0.5) });
				}
			}
		}
		// Put them in random order
		for (n = 0; n < 1000; n += 1) {
			i = defaultRandom.iRandom(Snake.itemLocations.length-1);
			j = defaultRandom.iRandom(Snake.itemLocations.length-1);
			temp = Snake.itemLocations[i];
			Snake.itemLocations[i] = Snake.itemLocations[j];
			Snake.itemLocations[j] = temp;
		}
	},

	// Returns a possible location for the item
	getItemLocation : function(kind) {
		"use strict";
		var xx, yy, n, items, i, ok;
		items = tbGame.findTokens("item");
		// Find a good location
		for (n = 0; n < Snake.itemLocations.length; n += 1) {
			Snake.lastItemLocation += 1;
			if (Snake.lastItemLocation >= Snake.itemLocations.length) { Snake.lastItemLocation = 0; }
			if (kind !== Snake.itemLocations[Snake.lastItemLocation].kind) { continue; }
			xx = Snake.itemLocations[Snake.lastItemLocation].x;
			yy = Snake.itemLocations[Snake.lastItemLocation].y;
			ok = true;
			if (Math.pow(Snake.snakeToken.headX()-xx,2) + Math.pow(Snake.snakeToken.headY()-yy,2) < Math.pow(4*Snake.cellSize,2)) {ok = false; }
			if (ok && Snake.snakeToken.checkCollision(xx, yy, Snake.cellSize, false)) { ok = false; }
			for (i = 0; i < items.length; i += 1) {
				if (Math.pow(items[i].x-xx,2) + Math.pow(items[i].y-yy,2) < Math.pow(2*Snake.cellSize,2)) { ok = false; break; }
			}
			if (ok) { return Snake.itemLocations[Snake.lastItemLocation]; }
		}
		return undefined;
	},

	
	// ****************************************
	// Dealing with goal, and score
	// ****************************************

	uiController : null,                // The user interface controller
	_s1 : 0, _s2 : 0, _s3 : 0,          // The star scores
	_smax : 0,                          // The maximum score for the bar
	_goalLength: 0,                     // The goal length
	_currentLength : 0,                 // The current length
	
	// Initialize the goal
	initGoal : function () {
		"use strict";
		Snake._goalLength = TG.settings.game.levels[Snake.level].general.goal;
		Snake._currentLength = 0;
		//Snake.uiController.setItemText(Snake._currentLength.toString() + "/" + Snake._goalLength.toString());
	},
	
	// Set the goal progression
	setGoal : function (length) {
		"use strict";
		Snake._currentLength = length;
		//Snake.uiController.setItemText(Snake._currentLength.toString() + "/" + Snake._goalLength.toString());
	},
	
	// Add to the goal progression
	addGoal : function(length) {
		"use strict";
		Snake.setGoal(Snake.getGoal() + length);
	},

	// Gets the goal progression
	getGoal : function() {
		"use strict";
		return Snake._currentLength;
	},

	// Returns whether the goal is reached
	reachedGoal : function() {
		"use strict";
		return Snake._currentLength >= Snake._goalLength;
	},

	// Initialize the score
	initScore : function() {
		"use strict";
		Snake._s1 = TG.settings.game.levels[Snake.level].general.star1;
		Snake._s2 = TG.settings.game.levels[Snake.level].general.star2;
		Snake._s3 = TG.settings.game.levels[Snake.level].general.star3;
		Snake._smax = Math.round(1.2*Snake._s3);
		//Snake.uiController.setScore(0);
		Snake.score.setValue(0);
		//Snake.uiController.addStar(100*Snake._s1/Snake._smax);
		//Snake.uiController.addStar(100*Snake._s2/Snake._smax);
		//Snake.uiController.addStar(100*Snake._s3/Snake._smax);
	},

	// Set the score
	setScore : function(score) {
		"use strict";
		Snake.score.addValue(score);
		//Snake.uiController.setScore(score);
		//Snake.uiController.setProgress(100*Snake.getScore()/Snake._smax);
	},

	// Adds something to the score
	addScore : function(score, showFloater, x, y) {
		"use strict";
		Snake.setScore(Snake.getScore() + score);
		//if (showFloater !== undefined && showFloater === true && score !== 0) {
		//  tbFloaters.addFloater(tbFloaters.numberFloater, score,
		//      x, y - TG.settings.game.floater.offsetScore,
		//      x, y - TG.settings.game.floater.offsetScore - TG.settings.game.floater.distanceScore,
		//      TG.settings.game.floater.durationScore * 1000,
		//      TG.settings.game.floater.delayScore * 1000);
		//}
	},

	// Gets the score
	getScore : function() {
		"use strict";
		return 0;
		//return Snake.uiController.getScore();
	},

	// Gets the number of stars
	getStars : function() {
		"use strict";
		var score = Snake.getScore();
		if (score < Snake._s1) { return 0; }
		if (score < Snake._s2) { return 1; }
		if (score < Snake._s3) { return 2; }
		return 3;
	}

};

