/////////////////////////////////////////////////////////////
// TokenFPS: A token that maintains the fps
//
// Copyright 2014 Tingly Games
// Last Changed: 11-3-2014
/////////////////////////////////////////////////////////////

var TokenFPS = function() {
	"use strict";
    this.depth = -10000;
	this.visible = true;		// Don't draw it
	this.active = true;			// Handle it
	this.group = 0;				// Different from default
	TG.functions.setLayerAndCanvas(this, TG.gameEffectsLayer);
	this.lastFPS = 0;
	this.timePassed = 0;
	this.steps = 0;
    this.minFPS = 0;
    this.totFPS = 0;
    this.totTime = 0;
	// Finally, add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "fps"]);
};

// Return the fps during the last second
TokenFPS.prototype.last = function() {
	"use strict";
	return this.lastFPS;
};

// Return the minimum fps
TokenFPS.prototype.min = function() {
	"use strict";
	return this.minFPS;
};

// Return the average fps
TokenFPS.prototype.average = function() {
	"use strict";
	return Math.floor(this.totFPS/this.totTime);
};

TokenFPS.prototype.handleBeginStep = function(timePassed) {
	"use strict";
	this.steps += 1;
	this.timePassed += timePassed;
	if (this.timePassed >= 1000){
		this.timePassed -= 1000;
		if(this.lastFPS > 0 && (this.minFPS <= 0 || this.steps <= this.minFPS)){
            this.minFPS = this.steps;
        }
        this.lastFPS = this.steps;
        this.steps = 0;
        this.totFPS += this.lastFPS;
        this.totTime += 1;
	}
};

TokenFPS.prototype.handleDraw = function() {
	"use strict";
	tbGraphics.drawText("FPS: " + this.lastFPS, 20, 20, "black",  "bold 12px Arial");
};

