/////////////////////////////////////////////////////////////
// LevelController
//
// This token globally controls a level (run of the game)
//
// Copyright 2014 Tingly Games
// Last Changed: 30-5-2014
/////////////////////////////////////////////////////////////


// The constructor for the LevelController game token
var LevelController = function() {
	"use strict";
	// Properties used by the engine
	this.depth = 0;
	this.active = false;
	this.visible = true;
	this.levelIdx = 0;          //levelIdx;             Disabled for FB testing
	this.timeStart = 0;
	this.timeFinished = 0;

	this.saveFile = undefined;  //TG.tmpSettings;

	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "play"]);
	
	this.ranks = TG.settings.game.levelEnd.ranks;
};

LevelController.prototype.loadStartDialog = function() {
	"use strict";
	var self = this;

	var _snakeCollection = SnakeCollection;

	PlayerDataService.getPlayerData(["saveState"])
	.then(function(data){
		self.saveFile = data.saveState;
		if(self.saveFile === undefined || self.saveFile === null){
			self.saveFile = _snakeCollection;
			self.saveData();
			self.whatsNew = new tgfDialogs.WhatsNew();
		} else {
			if(_snakeCollection["global"]["ver"] !== self.saveFile["global"]["ver"]){
				var backupEgg = 0;
	
				for(var prop in self.saveFile["snakes"]){
					_snakeCollection["snakes"][prop] = self.saveFile["snakes"][prop];
					if(self.saveFile["snakes"][prop]["unlocked"] && prop > 0){
						backupEgg++;
					}
				}
	
				//SORRY FUTURE READER :)
				if(self.saveFile["global"]["ver"] === "1.1"){
					self.saveFile["eggsCollected"] = backupEgg;
				}
				//////////////////////////
	
				_snakeCollection["eggsCollected"] = self.saveFile["eggsCollected"];
				_snakeCollection["speedSelection"] = self.saveFile["speedSelection"];
				_snakeCollection["skinSelection"] = self.saveFile["skinSelection"];
	
				self.saveFile = _snakeCollection;
				self.whatsNew = new tgfDialogs.WhatsNew();
			}
		}
	
		self.gameStartDialog = new tgfDialogs.GameStart({
			snakeCollection     : self.saveFile,
			callback            : self._startTutorial,
			difficultySettings  : TG.settings.game.difficultySettings,
			context             : self,
			onUpdate			: function(data){
				self.saveFile = data;
			}
		});
	
		if(self.whatsNew){
			self.whatsNew.doHide = function(){
				self.gameStartDialog.show();
			};
			self.whatsNew.show();
		} else {
			self.gameStartDialog.show();
		}
	});
};

