// End the level when the game is over
LevelController.prototype._endLevel = function(won){
	"use strict";

	var self = this;
	this.active = false;
	this.collectibleController.active = false;

	if(Snake.score.getValue() >= Snake.highscore.getValue()){
		this.saveFile.snakes[this.levelIdx].highscore = Snake.score.getValue();
	}

	tgfHooks.execute("gameCompleted", this.levelIdx, Snake.score.getValue());
	this.saveData();

	this.date = new Date();

	this.timeFinished = this.date.getTime();

	var playSession = this.timeFinished - this.timeStart;

	ContollerUsage.used();

	this.gameOverDialog = new tgfDialogs.GameEnd
	({
		ranks   : self.ranks,
		points  : Snake.score.getValue(),
	});
	
	tgfHooks.execute("showAd", function(){
		self.gameOverDialog.show();
	});
};

// handleAdd is called when the token is (re-) added to the game.
LevelController.prototype.handleAdd = function() {
	"use strict";
	var highscore, xx, ww, dd, factor;
	
	this.bg = new Background();

	this.showDebug = TG.settings.game.general.showDebug;
	if (this.showDebug) { new TokenFPS(); }

	if (highscore === undefined || highscore === null) { highscore = 0; }
	// Initialize the game
	Snake.controller = this;
	Snake.mode = Snake.gameModeInit;

	//Snake.initLevel(this.levelIdx);
};

// handleRemove is called when the token is removed from the game.
LevelController.prototype.handleRemove = function() 
{
	"use strict";
	tbGame.removeTokens("fps");
	tbGame.removeTokens("item");
	tbGame.removeTokens("extra");
	this.gameOverDialog.hide();
	this.gameOverDialog = undefined;
	Snake.ui.hide();
	Snake.ui = undefined;
	this.bg = undefined;
	this.walls = undefined;
	this.collectibleController = undefined;
	this.factScreen = undefined;
};

// handleAlarm is called if a global alarm is reached.
LevelController.prototype.handleAlarm = function(alarm) {
	"use strict";
	if (alarm === "lost") {
		this._endLevel(false);
	}
	if (alarm === "end") {
		this._endLevel(true);
	}
	if (Snake.mode === Snake.gameModePlaying) { 
		if (alarm === "lesseggs" ) {
			this.eggCount = TG.settings.game.levels[Snake.level].egg.count;
		}
		if (alarm === "lesschickens" ) {
			this.chickenCount = TG.settings.game.levels[Snake.level].chicken.count;
		}
	}
};


