/////////////////////////////////////////////////////////////
// TokenCollectible
//
// This token displays and handles an egg
//
// Copyright 2014 Tingly Games
// Last Changed: 06-06-2014
/////////////////////////////////////////////////////////////

var collectibleTypes = 
{
	'apple' 			: 0,
	'timedCollectible' 	: 1,
	'egg' 				: 2
};

var collectibleAnimationState	=
{
	'appearing'			: 0,
	'idle'				: 1,
	'disappearing'		: 2
};

// The constructor for the TokenCollectible game token.
var TokenCollectible = function(x, y, onEatenCallback, onEatenContext) 
{
	"use strict";
	// Properties used by the engine
	this.depth = 10 - y/1000;	// Higher items should appear below lower items
	this.visible = true;
	this.active = true;
	this.group = 0;
	//TG.functions.setLayerAndCanvas(this, TG.gameEffectsLayer);
	// Your own properties
	this.x = x;
	this.y = y;
	// Get the settings
	this.radius = TG.settings.game.egg.radius;
	this.eatRadius = TG.settings.game.egg.eatRadius;
	this.grow = TG.settings.game.levels[Snake.level].egg.grow;
	this.score = DifficultyController.appleScore;
	this.canEat = true;
	// Set the image	
	
	this.onEatenCallback	= onEatenCallback;
	this.onEatenContext		= onEatenContext;
	this.animationState		= collectibleAnimationState['appearing'];
};

TokenCollectible.prototype.setVariablesAndAddToGame = function(collectibleType, score)
{	
	this.score = score;
	this.collectibleType	= collectibleType;
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "item", 'collectible_' + collectibleType, "play"]);
};

// remove the item smoothly
TokenCollectible.prototype.removeSmooth = function() { 
	"use strict";
	this.lifeTime = this.maxTime-this.appearTime;
};

TokenCollectible.prototype.isOnSameLevel = function(snake)
{
	"use strict";
	if (snake.direction === 0 || snake.direction === 180)
		return Snake.vCell(snake.headY()) === Snake.vCell(this.y);
	else return Snake.vCell(snake.headX()) === Snake.vCell(this.x);
};

TokenCollectible.prototype.handleState = function(timePassed)
{
	switch (this.animationState)
	{
		case collectibleAnimationState['appearing']:
			this.handleAppearingState(timePassed);
			this.canEat = true;
			break;

		case collectibleAnimationState['idle']:
			this.handleIdleState(timePassed);
			break;

		case collectibleAnimationState['disappearing']:
			this.handleDisappearingState(timePassed);
			this.canEat = false;
			break;
	};
};

TokenCollectible.prototype.handleAppearingState	= function(timePassed) 
{ 
	"use strict";

	// Do overrides here
};

TokenCollectible.prototype.handleIdleState = function(timePassed) 
{ 
	"use strict";

	// Do overrides here
};

TokenCollectible.prototype.handleDisappearingState = function(timePassed) 
{ 
	"use strict";

	// Do overrides here
};

TokenCollectible.prototype.handleEndStep = function(timePassed) 
{ 
	"use strict";

	var xx, yy, dd;

	this.handleState(timePassed);

	this.lifeTime += timePassed / 1000;

	// Check whether the egg is eaten
	xx = this.x - Snake.snakeToken.headX();
	yy = this.y - Snake.snakeToken.headY();

	dd = this.eatRadius + Snake.snakeToken.headRadius;

	// Play the close mouth animation when the snake is too far away from the target.
	if (!(xx*xx + yy*yy < Snake.cellSize * Snake.cellSize * 2))
	{
		Snake.snakeToken.playCloseMouthAnimation(); 
	} 
	else if (this.isOnSameLevel(Snake.snakeToken) && this.canEat)
	{
		Snake.snakeToken.playOpenMouthAnimation();
	}
	
	if (xx * xx + yy * yy < dd * dd) 
	{	
		this.onEaten();
	}
	// Remove the egg when its life time is over
	if (this.lifeTime > this.maxTime) 
	{
		tbGame.removeToken(this);

		return;
	}
};

TokenCollectible.prototype.onEaten = function()
{
	"use strict";

	Snake.snakeToken.playCloseMouthAnimation();	//play the close mouth animation when the snake is close enough to eat the target.

	if(!this.canEat){
		return;
	}

	Snake.snakeToken.elementDesired += this.grow;

	Snake.addGoal(1);

	Snake.addScore(this.score, true, this.x, this.y);
	if(Snake.score.getValue() > Snake.highscore.getValue()){
		Snake.highscore.setValue(Snake.score.getValue());
	}

	tbGame.removeToken(this);

	if (this.onEatenCallback)
	{
		this.onEatenCallback.call(this.onEatenContext, this);
	}
};

TokenCollectible.prototype.handleDraw = function() 
{
	"use strict";
};


