/////////////////////////////////////////////////////////////

// TODO: Shove in engine -Nils
// TEMPORARILY, FOR AS LONG AS IT IS NOT IN THE BUILD
tbMath.direction = function(x1, y1, x2, y2)
{
	"use strict";

	var xx = x2-x1, yy = y2-y1;

	return tbMath.radToDeg(Math.atan2(-yy, xx));
};

tbMath.projectionX = function(direction, length)
{
	"use strict";

	return length * Math.cos(tbMath.degToRad(direction));
};

tbMath.projectionY = function(direction, length)
{
	"use strict";

	return - length * Math.sin(tbMath.degToRad(direction));
};

// The constructor for the TokenSnake game token. 
var TokenSnake = function(x, y) 
{
	"use strict";

	// Properties used by the engine
	this.depth = 0; 
	this.visible = true;
	this.active = true;
	this.group = 0;

	// Dealing with interaction
	this.finger = -1;                   // The finger we move towards
	this.fingerDown = false;            // Whether that finger is down
	this.fingerX = 0;                   // X-position of the finger we move towards
	this.fingerY = 0;                   // Y-position of the finger we move towards
	this.adaptDirection = false;        // Whether to adapt the direction towards the last finger positions
	this.allowKeyboard = TG.settings.game.interaction.keyboard;
	this.allowTouchInput = TG.settings.game.interaction.touchInput;
	this.continuous = TG.settings.game.interaction.continuous;
	this.orthogonal = TG.settings.game.interaction.orthogonal;
	this.directionMinDistance = TG.settings.game.interaction.deadDistance;
	this.directionDeadZone = TG.settings.game.interaction.deadDirection;
	this.turnRadius = TG.settings.game.levels[Snake.level].snake.turnRadius;

	// Fill in the setting
	this.headRadius = TG.settings.game.snake.headRadius;
	this.bodyRadius = TG.settings.game.snake.bodyRadius;
	this.speedStart = TG.settings.game.levels[Snake.level].snake.speedStart;
	this.speedIncr = TG.settings.game.levels[Snake.level].snake.speedIncrease;
	this.speedMin = TG.settings.game.levels[Snake.level].snake.speedMin;
	this.speedMax = TG.settings.game.levels[Snake.level].snake.speedMax;
	this.elementDesired = TG.settings.game.levels[Snake.level].snake.elements;
	this.elementDistance = TG.settings.game.snake.elementDistance;
	this.autoGrow = TG.settings.game.levels[Snake.level].snake.autoGrow;
	this.exitAuto = TG.settings.game.snake.exitAuto;
	this.exitDistance = TG.settings.game.snake.exitDistance;
	this.exitElements = TG.settings.game.snake.exitElements;
	this.grid = TG.settings.game.grid;

	// Initialize the snake
	this.headTween = null;
	this.speed = DifficultyController.snakeSpeed;
	this.biteAnimationState = 'none';
	this.biteAnimationTime  = TG.settings.game.snake.biteAnimationTime / (this.speed * 0.01);
	this.currentBiteTime    = 0;
	this.biteAnimationFrame = 0;
	this.startX = x;
	this.startY = y;
	this.direction = 90;
	this.initPath();
	this.addPath(x, y);
	this.elementCount = 2;              // Number of elements in the snake
	this.hiddenElements = 0;            // Number of elements at the start of the snake that must be hidden
	this.initElements();
	this.updateElements();
	this.translucent = false;           // Whether the snake can self-intersect
	this.bodyImage = SkinController.bodyCollection[SkinController.skin];
	this.headImage = SkinController.headCollection[SkinController.skin];;

	this.currentDirection = {
		x: 0,
		y: 0
	};

	this.directionValues = {
		positive: 100000,
		negative: -100000
	};

	this.swipeDir = null;
	this.swipeX = 0;
	this.swipeY = 0;
	this.swipeTime = TG.settings.game.swipe.time;
	this.hasSwipe = TG.settings.game.swipe.hasSwipe;
	this.curSwipeTime = this.swipeTime;

	this.inputListLength = 2;

	this.inputList = [];

	this.didTurnOnCurrentCell = false;

	// List of collectibles in snake's belly (for visual enhancement)
	this.collectibles = [];

	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "item", "play"]);

	// Now get going
	tbGame.setAlarm('newSnakeElement', 50, 100000000, this);
};

TokenSnake.prototype.handleAdd = function()
{
	this.currentDirection.x = this.directionValues.positive;
	this.currentDirection.y = this.headY();

	// Deal with the start
	if (Snake.mode === Snake.gameModeStarted) 
	{
		tbAudio.play(a_level_start);

		this.direction = tbMath.direction(this.headX(), this.headY(), this.currentDirection.x, this.currentDirection.y);

		Snake.mode = Snake.gameModePlaying;
	}
};

// Initialize the path of the snake
TokenSnake.prototype.initPath = function() 
{
	"use strict";

	var i;

	// Definitely long enough for any snake
	this.path = new Array(10000);

	for (i = 0; i < this.path.length; i += 1) 
	{
		this.path[i] = {
			x: 0, 
			y: 0
		};
	}

	this.pathHead = 0;
	this.pathLength = 0;
};

// Add a point to the path
TokenSnake.prototype.addPath = function(x, y) 
{
	"use strict";

	this.path[this.pathHead].x = x;
	this.path[this.pathHead].y = y;

	this.pathHead += 1;
	this.pathLength += 1;
};

// reduce the length of the path
TokenSnake.prototype.reducePath = function() 
{
	"use strict";

	var i, n;

	n = this.pathHead - this.pathLength;

	for (i = 0; i < this.pathLength; i += 1) 
	{
		this.path[i].x = this.path[i+n].x;
		this.path[i].y = this.path[i+n].y;
	}
	
	this.pathHead = this.pathLength;
};

// Initialize the list of elements
TokenSnake.prototype.initElements = function() 
{
	"use strict";

	var i;

	// Definitely long enough for any snake
	this.elements = new Array(2000);

	for (i = 0; i < this.elements.length; i += 1) 
	{
		this.elements[i] = {
			x: 0,
			y: 0, 
			kind: 0, 
			direction: 0,
			scaleX: 1,
			scaleY: 1,
			targetScaleX: 1,
			targetScaleY: 1,
			collectible: null
		};
	}
};

/**
 * Update elements every frame, based on path values
 */
TokenSnake.prototype.updateElements = function() 
{
	"use strict";

	var i, n, len, xx, yy, dd;

	// Deal with hidden elements
	if (Snake.mode !== Snake.gameModeExiting) 
	{ 
		this.hiddenElements = 0; 
	}

	// Add the head
	this.elements[0].x = this.headX();
	this.elements[0].y = this.headY();
	this.elements[0].kind = 0;
	// this.elements[0].direction = this.direction;

	// Add the other elements
	n = this.pathHead-1;

	len = 0;

	for (i = 1; i < this.elementCount; i += 1) 
	{
		// Find the correct place in the path
		if (i >= this.hiddenElements) 
		{
			while (n > this.pathHead-this.pathLength &&
				(i-this.hiddenElements)*this.elementDistance >= len + tbMath.distance(this.path[n].x, this.path[n].y, this.path[n-1].x, this.path[n-1].y)) 
			{
				len += tbMath.distance(this.path[n].x, this.path[n].y, this.path[n-1].x, this.path[n-1].y);
				n -= 1;
			}

			// Compute the position
			if (n === this.pathHead-this.pathLength) 
			{
				xx = this.path[n].x;
				yy = this.path[n].y;
			} 
			else 
			{
				dd = ((i-this.hiddenElements)*this.elementDistance-len) / tbMath.distance(this.path[n].x, this.path[n].y, this.path[n-1].x, this.path[n-1].y);

				xx = this.path[n].x + dd * (this.path[n-1].x - this.path[n].x);
				yy = this.path[n].y + dd * (this.path[n-1].y - this.path[n].y);
			}

		}
		else 
		{
			xx = this.headX();
			yy = this.headY();
		}

		this.elements[i].x = xx;
		this.elements[i].y = yy;

		this.elements[i].kind = 1 + (i % 2);

		// Set the direction correctly
		if (this.elements[i].x === this.elements[i-1].x && this.elements[i].y === this.elements[i-1].y) 
		{
			this.elements[i].direction = this.elements[i-1].direction;
		} 
		else 
		{
			this.elements[i].direction = tbMath.direction(this.elements[i].x, this.elements[i].y, this.elements[i-1].x, this.elements[i-1].y);
		}
	}

	// Correct the kind of the tail
	this.elements[this.elementCount-1].kind = 3;

	// Remove unused part of the path
	this.pathLength = this.pathHead - n;

	if (this.pathHead > this.path.length-2) 
	{ 
		this.reducePath(); 
	}
};

// Returns the x-position of the head
TokenSnake.prototype.headX = function() 
{
	"use strict";

	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return 0; 
	}

	return this.path[this.pathHead-1].x;
};

// Returns the y-position of the head
TokenSnake.prototype.headY = function() 
{
	"use strict";

	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return 0; 
	}

	return this.path[this.pathHead-1].y;
};

TokenSnake.prototype.setHeadX = function(x) 
{
	"use strict";

	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return; 
	}

	this.path[this.pathHead-1].x = x;
};

// Returns the y-position of the head
TokenSnake.prototype.setHeadY = function(y) 
{
	"use strict";
	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return; 
	}

	this.path[this.pathHead-1].y = y;
};

// Returns the x-position of the tail
TokenSnake.prototype.tailX = function() 
{
	"use strict";
	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return 0; 
	}

	return this.path[this.pathHead-this.pathLength].x;
};

// Returns the y-position of the tail
TokenSnake.prototype.tailY = function() 
{
	"use strict";

	if (Snake.mode === Snake.gameModeInit) 
	{ 
		return 0; 
	}

	return this.path[this.pathHead-this.pathLength].y;
};

// check whether the snake intersects the position with the margin. noHead means that no collisions with the head should be checked
TokenSnake.prototype.checkCollision = function(x, y, margin, noHead) 
{
	"use strict";

	var i, start;

	if (Snake.mode === Snake.gameModeInit) 
	{
		return false;
	}

	if (!noHead && Math.pow(x-this.elements[0].x, 2) + Math.pow(y-this.elements[0].y, 2) < Math.pow(margin+this.headRadius, 2))
	{
		return true;
	}

	if (noHead) 
	{
		start = 8; 
	}
	else 
	{
		start = 1; 
	}

	for (i = start; i < this.elementCount; i += 1) 
	{
		if (Math.pow(x-this.elements[i].x, 2) + Math.pow(y-this.elements[i].y, 2) < Math.pow(margin+this.bodyRadius, 2))
		{
			return true;
		}
	}

	return false;
};

TokenSnake.prototype.handleKeyDown = function(keyCode) 
{
	"use strict";

	if (!this.allowKeyboard) 
	{ 
		return; 
	}

	this.key = keyCode;

	switch (keyCode) 
	{
		case tbKeyCodes.vkLeft:
			
			this.turnLeft();
			ContollerUsage.keyboardClick();

			break;

		case tbKeyCodes.vkRight:
			
			this.turnRight();
			ContollerUsage.keyboardClick();

			break;

		case tbKeyCodes.vkUp:
			
			this.turnUp();
			ContollerUsage.keyboardClick();

			break;

		case tbKeyCodes.vkDown:
			
			this.turnDown();
			ContollerUsage.keyboardClick();

			break;
	}
};

TokenSnake.prototype.handleKeyUp = function(keyCode) 
{
	"use strict";
};

TokenSnake.prototype.handleTouchDown = function(finger, x, y) 
{
	"use strict";
	//if(this.finger > -1 || finger > 0){
	//	return;
	//}

	this.finger = finger;

	this.fingerDown = true;

	this.fingerX = tbGame.touchX(this.finger);

	this.fingerY = tbGame.touchY(this.finger);

	if(this.fingerY > tgfScale(718)){
		return;
	}

	// Deal with orthogonal motion
	if (this.orthogonal)
	{

		//if(this.hasSwipe){
		//	return;
		//}

		switch(DifficultyController.controllerOption){
			case 0:
				if (this.direction < 45 || this.direction > 315 || (this.direction > 135 && this.direction < 225))
				{
					if (this.fingerY < this.headY() - this.directionMinDistance)
					{
						this.turnUp();
						ContollerUsage.touchClick();
					}
					else if (this.fingerY > this.headY() + this.directionMinDistance)
					{
						this.turnDown();
						ContollerUsage.touchClick();
					}
				}
				else
				{
					if (this.fingerX < this.headX() - this.directionMinDistance)
					{
						this.turnLeft();
						ContollerUsage.touchClick();
					}
					else if (this.fingerX > this.headX() + this.directionMinDistance)
					{
						this.turnRight();
						ContollerUsage.touchClick();
					}
				}
				break;
			case 1:
				if(this.direction > 135 && this.direction < 225){
					if (this.fingerX < tgfGraphics.areaWidth / 2)
					{
						this.turnDown();
						ContollerUsage.touchClick();
					}
					else if (this.fingerX > tgfGraphics.areaWidth / 2)
					{
						this.turnUp();
						ContollerUsage.touchClick();
					}
				} else if(this.direction < 45 || this.direction > 315){
					if (this.fingerX < tgfGraphics.areaWidth / 2)
					{
						this.turnUp();
						ContollerUsage.touchClick();
					}
					else if (this.fingerX > tgfGraphics.areaWidth / 2)
					{
						this.turnDown();
						ContollerUsage.touchClick();
					}
				} else {
					if(this.direction > 225 && this.direction < 315){
						if (this.fingerX < tgfGraphics.areaWidth / 2)
						{
							this.turnRight();
							ContollerUsage.touchClick();
						}
						else if (this.fingerX > tgfGraphics.areaWidth / 2)
						{
							this.turnLeft();
							ContollerUsage.touchClick();
						}
					} else {
						if (this.fingerX < tgfGraphics.areaWidth / 2)
						{
							this.turnLeft();
							ContollerUsage.touchClick();
						}
						else if (this.fingerX > tgfGraphics.areaWidth / 2)
						{
							this.turnRight();
							ContollerUsage.touchClick();
						}
					}
				}
				break;
			case 2:
				if (this.direction < 45 || this.direction > 315 || (this.direction > 135 && this.direction < 225))
				{
					if (this.fingerY < tgfScale(718) / 2)
					{
						this.turnUp();
						ContollerUsage.touchClick();
					}
					else if (this.fingerY > tgfScale(718) / 2)
					{
						this.turnDown();
						ContollerUsage.touchClick();
					}
				}
				else
				{
					if (this.fingerX < tgfGraphics.areaWidth / 2)
					{
						this.turnLeft();
						ContollerUsage.touchClick();
					}
					else if (this.fingerX > tgfGraphics.areaWidth / 2)
					{
						this.turnRight();
						ContollerUsage.touchClick();
					}
				}
				break;
				break;
		}
	}
	else 
	{
		this.adaptDirection = true;
	}
};

