TokenSnake.prototype.handleAlarm = function(alarm) 
{
	"use strict";
	
	// Grow the snake when required
	if (Snake.mode === Snake.gameModePlaying || Snake.mode === Snake.gameModeReady) 
	{
		if (alarm === 'newSnakeElement' && this.elementCount < this.elementDesired) 
		{
			this.elementCount += 1;
		}

		if (alarm === 'newSnakeElement' && this.elementCount > this.elementDesired) 
		{
			this.elementCount -= 1;
		}

		if (alarm === "collisions")
		{
			this.translucent = false;
		}
	}
};

TokenSnake.prototype.computeNewDirection = function(timePassed, xGoal, yGoal, checkBounds) 
{
	"use strict";

	var newDir = tbMath.direction(this.headX(), this.headY(), xGoal, yGoal),
		curDir = this.direction,
		dirChange, maxChange;

	if (newDir < 0)
	{
		newDir += 360;
	}

	// Compute new direction
	if (newDir < curDir - 180) 
	{ 
		newDir += 360; 
	}

	if (newDir > curDir + 180) 
	{ 
		newDir -= 360; 
	}

	//round to the nearest right angle.
	//hack so check direction - Jur.
	newDir  = Math.round(newDir / 90) * 90;

	maxChange = this.speed * 180 / (Math.PI * this.turnRadius);

	dirChange = maxChange * timePassed / 1000;

	if (newDir < curDir) 
	{
		curDir -= Math.min(dirChange, curDir-newDir); 
	}

	if (newDir > curDir) 
	{
		curDir += Math.min(dirChange, newDir-curDir); 
	}

	if (curDir < 0) 
	{ 
		curDir += 360;

		this.elements[0].direction += 360;
	}

	if (curDir >= 360) 
	{
		curDir -= 360;

		this.elements[0].direction -= 360;
	}

	this.direction = curDir;

	// Hacky solution to check if tween exists, or create new one -Nils
	this.headTween = this.headTween || new tbTween(this.elements[0]);

	this.headTween['to']({direction: this.direction});

	// Make sure head rotates fast enough on every speed
	var duration = TG.settings.game.snake.headRotationSpeed * this.speed;

	this.headTween['duration'](duration);

	this.headTween['start']();
};

TokenSnake.prototype.checkCollisions = function() 
{
	"use strict";

	var col = Snake.checkCollision(this.elements[0].x, this.elements[0].y, this.headRadius/2);

	if (!this.translucent && !col) 
	{
		col = this.checkCollision(this.elements[0].x, this.elements[0].y, this.headRadius/2, true);     
	}

	if (col) 
	{
		tbAudio.play(a_level_end);

		tbGame.setAlarm("lost", TG.settings.game.collision.duration * 1000, 0, Snake.controller);

		new TokenCrash(this.headX(), this.headY() - TG.settings.game.collision.offset);

		Vibration.lose();

		Snake.mode = Snake.gameModeCollision;
	}
};

// TODO: see if we can remove this function -Nils
TokenSnake.prototype.screenEnd = function(x, y, isHead)
{
	var _pos = {x: x, y: y};

	if (x < tgScale(-46))
	{
		_pos.x = (Snake.cellSize * Snake.horNumber) + tgScale(45);
	} 
	else if (x > (Snake.cellSize * Snake.horNumber) + tgScale(46))
	{
		_pos.x = tgScale(-45);
	}

	if (isHead)
	{
		this.addPath(_pos.x, _pos.y);
	}

	return _pos;
};

TokenSnake.prototype.allowToTurn = function(x, y)
{
	"use strict";

	var turningAllowed = this.isOnCellCenterX(x) && this.isOnCellCenterY(y);

	if (this.inputList.length === 0)
	{
		return false;
	}

	var targetDirection = this.inputList[0];

	if (targetDirection.x === this.currentDirection.x * -1)
	{
		this.inputList.splice(0, 1);

		return this.allowToTurn(x, y);
	}

	if (targetDirection.y === this.currentDirection.y * -1)
	{
		this.inputList.splice(0, 1);

		return this.allowToTurn(x, y);
	}

	if (turningAllowed && !this.didTurnOnCurrentCell)
	{
		var gridX = Snake.hCell(x);

		var cellPosX = Snake.xCell(gridX);

		var gridY = Snake.vCell(y);

		var cellPosY = Snake.yCell(gridY);

		this.addPath(cellPosX, cellPosY);

		this.adaptDirection = false;

		this.didTurnOnCurrentCell = true;

		this.currentDirection.x = targetDirection.x;
		this.currentDirection.y = targetDirection.y;

		this.inputList.splice(0, 1);
	}

	return turningAllowed;
};

TokenSnake.prototype.isOnCellCenterX = function(x)
{
	var gridX = Snake.hCell(x);

	var cellPosX = Snake.xCell(gridX);

	if (x > cellPosX - this.grid.zone && x < cellPosX + this.grid.zone)
	{
		return true;
	}

	return false;
};

TokenSnake.prototype.isOnCellCenterY = function(y)
{
	var gridY = Snake.vCell(y);

	var cellPosY = Snake.yCell(gridY);

	if (y > cellPosY - this.grid.zone && y < cellPosY + this.grid.zone)
	{
		return true;
	}

	return false;
};

TokenSnake.prototype.tryEnableInput = function(x, y)
{
	if (!this.isOnCellCenterX(x) || !this.isOnCellCenterY(y))
	{
		this.didTurnOnCurrentCell = false;
	}
};

