TokenSnake.prototype.checkSwipe = function(x, y){
	"use strict";

	var dd = 0;
	x -= this.headX();
	y -= this.headY();

	this.nextXdir = 0;
	this.nextYdir = 0;
	if (x < 0 && y < 0) {
		if (-x > -y) {
			this.turnLeft();
		} else {
			this.turnUp();
		}
	}
	if (x < 0 && y >= 0) {
		if (-x > y) {
			this.turnLeft();
		} else {
			this.turnDown();
		}
	}
	if (x >= 0 && y < 0) {
		if (x > -y) {
			this.turnRight();
		} else {
			this.turnUp();
		}
	}
	if (x >= 0 && y >= 0) {
		if (x > y) {
			this.turnRight();
		} else {
			this.turnDown();
		}
	}
};

// handleEndStep is called each step after processing other events (before draw).
TokenSnake.prototype.handleEndStep = function(timePassed) 
{
	"use strict";

	var items, i, vec;

	// Update the finger position
	if (this.fingerDown && !this.orthogonal)
	{
		this.fingerX = tbGame.touchX(this.finger);
		this.fingerY = tbGame.touchY(this.finger);

		this.adaptDirection = true;
	}

	//if(this.hasSwipe && tbGame.touchDown(0)){
	//	//this.curSwipeTime -= timePassed;
	//	//this.checkSwipe(false);
	//	this.checkSwipe(tbGame.touchX(0), tbGame.touchY(0));
	//}

	var currentSpeed = this.speed * timePassed / 1000;

	// Check whether anything needs to be done
	switch (Snake.mode)
	{
		case Snake.gameModeInit: 
		case Snake.gameModeCollision: 
		case Snake.gameModeFinished: 
		case Snake.gameModeOver: 
			break;

		case Snake.gameModeStarted:

			this.direction = tbMath.direction(this.headX(), this.headY(), this.currentDirection.x, this.currentDirection.y);

			break;

		case Snake.gameModePlaying:

			if (this.inputList.length > 0) 
			{
				var allow = this.allowToTurn(this.headX(), this.headY());

				if (allow)
				{
					this.computeNewDirection(timePassed, this.currentDirection.x, this.currentDirection.y, true);
				}
			}

			this.tryEnableInput(this.headX(), this.headY());

			this.addPath(this.headX() + tbMath.projectionX(this.direction, currentSpeed), 
							this.headY() + tbMath.projectionY(this.direction, currentSpeed));

			this.updateElements();

			this.checkCollisions();

			this.clearCollectibles();

			this.animateBite(timePassed);

			break;

		case Snake.gameModeReady:

			if (tbMath.distance(this.headX(), this.headY(), this.startX, this.startY) < this.exitAuto) 
			{
				this.computeNewDirection(timePassed, this.startX, this.startY, false); 
			} 
			else if (this.adaptDirection) 
			{
				this.computeNewDirection(timePassed, this.currentDirection.x, this.currentDirection.y, true); 
			}

			this.addPath(this.headX() + tbMath.projectionX(this.direction, currentSpeed), 
							this.headY() + tbMath.projectionY(this.direction, currentSpeed));

			if (tbMath.distance(this.headX(), this.headY(), this.startX, this.startY) < this.exitDistance) 
			{
				Snake.mode = Snake.gameModeExiting;

				this.hiddenElements = 0;
				
				this.path[this.pathHead-1].x = this.startX;
				this.path[this.pathHead-1].y = this.startY;

				items = tbGame.findTokens("arrow");

				for (i = 0; i < items.length; i += 1) 
				{
					items[i].removeSmooth();
				}
			}

			this.updateElements();

			this.checkCollisions();

			break;

		case Snake.gameModeExiting:

			this.hiddenElements += this.exitElements * timePassed / 1000;

			if (this.hiddenElements > this.elementCount) 
			{
				Snake.mode = Snake.gameModeFinished;
			}

			this.updateElements();

			break;
	}

	this.headTween && this.headTween.update();
};

// handleDraw is called at the end of a step to draw the token.
TokenSnake.prototype.handleDraw = function() 
{
	"use strict";

	var alpha = 1;

	if (this.translucent) 
	{ 
		alpha = 0.6; 
	}

	switch (Snake.mode) 
	{
		case Snake.gameModeInit: 
		case Snake.gameModeFinished: 
		case Snake.gameModeOver: 
			break;
			
		case Snake.gameModeStarted:

			this.handleDrawHead(alpha);

			break;

		case Snake.gameModePlaying:
		case Snake.gameModeReady:
		case Snake.gameModeCollision:
		case Snake.gameModeExiting:

			this.handleDrawBody(alpha);

			this.handleDrawHead(alpha);

			break;
	}
};

TokenSnake.prototype.handleDrawHead = function(alpha)
{
	"use strict";

	var head = this.elements[0];

	this.setElementScale(head);

	this.headImage.drawExt(
		this.biteAnimationFrame, 
		head.x, 
		head.y, 
		head.scaleX, 
		head.scaleY, 
		head.direction, 
		alpha);
};

TokenSnake.prototype.handleDrawBody = function(alpha)
{
	var i;

	for (i = this.elementCount - 1; i > this.hiddenElements; i -= 1) 
	{
		var element = this.elements[i];

		if (i !== this.elementCount - 1)
		{
			this.scaleByCollectible(element);
		}

		this.setElementScale(element);

		this.bodyImage.drawExt(
			element.kind, 
			element.x, 
			element.y, 
			element.scaleX, 
			element.scaleY, 
			element.direction, 
			alpha);
	}
};

TokenSnake.prototype.setElementScale = function(element)
{   
	// The rotation values seem to get reset by a value of 360 after a certain rotation value
	// Check if element is upside down
	if (element.direction <= -90 && element.direction >= -180 ||
		element.direction >= 135)
	{
		element.scaleY = -element.targetScaleY;
	}
	else
	{
		element.scaleY = element.targetScaleY;
	}

	element.scaleX = element.targetScaleX;
};

TokenSnake.prototype.scaleByCollectible = function(element)
{
	// TODO: move to a settings file -Nils
	var maxDistance = 25;

	var minScale = 1;
	var maxScale = 3;

	var scaleDifference = maxScale - minScale;

	var willScale = false;

	this.collectibles.forEach(function(collectible)
	{
		var distance = tbMath.distance(collectible.x, collectible.y, element.x, element.y);

		if (distance > maxDistance)
		{
			return;
		}

		willScale = true;

		var scaleDistance = maxDistance - distance;

		var scaleMultiplier = scaleDistance * 0.01;

		var scale = minScale + scaleDifference * scaleMultiplier;

		element.targetScaleX = scale;
		element.targetScaleY = scale;

		collectible.active = true;

		element.collectible = collectible;

	}, this);

	if (!willScale)
	{
		element.targetScaleX = minScale;
		element.targetScaleY = minScale;

		element.collectible = null;
	}
};

TokenSnake.prototype.addCollectible = function(collectible)
{
	// Create smaller collectible object
	var collectibleObject = {
		x: collectible.x,
		y: collectible.y,
		active: false
	};

	this.collectibles.push(collectibleObject);
};

TokenSnake.prototype.clearCollectibles = function()
{
	var i, k;

	var unusedCollectibleIndices = [];

	for (i = 0; i < this.collectibles.length; i++)
	{
		var collectible = this.collectibles[i];

		var isCollectibleActive = false;

		for (k = this.elementCount - 1; k > this.hiddenElements; k -= 1)
		{
			var element = this.elements[k];

			if (!collectible.active || element.collectible === collectible)
			{
				isCollectibleActive = true;
			}
		}

		if (!isCollectibleActive)
		{
			unusedCollectibleIndices.push(i);
		}
	}

	unusedCollectibleIndices.forEach(function(index)
	{
		this.collectibles.splice(index, 1);
	}, this);
};

TokenSnake.prototype.handleButtonDown = function(id)
{
	"use strict";

	switch (id)
	{
		case 'button_up':

			this.turnUp();
			ContollerUsage.buttonsClick();

			break;

		case 'button_left':

			this.turnLeft();
			ContollerUsage.buttonsClick();

			break;

		case 'button_right':

			this.turnRight();
			ContollerUsage.buttonsClick();

			break;

		case 'button_down':

			this.turnDown();
			ContollerUsage.buttonsClick();

			break;
	}
};

TokenSnake.prototype.turnLeft = function()
{
	var direction = {
		x: this.directionValues.negative,
		y: this.headY()
	};

	this.addToInputList(direction);

	this.adaptDirection = true;
};

TokenSnake.prototype.turnRight = function()
{
	var direction = {
		x: this.directionValues.positive,
		y: this.headY()
	};

	this.addToInputList(direction);

	this.adaptDirection = true;
};

TokenSnake.prototype.turnUp = function()
{
	var direction = {
		x: this.headX(),
		y: this.directionValues.negative
	};

	this.addToInputList(direction);

	this.adaptDirection = true;
};

TokenSnake.prototype.turnDown = function()
{
	var direction = {
		x: this.headX(),
		y: this.directionValues.positive
	};

	this.addToInputList(direction);

	this.adaptDirection = true;
};

TokenSnake.prototype.addToInputList = function(direction)
{
	if (this.inputList.length === this.inputListLength)
	{
		this.inputList[this.inputListLength - 1] = direction;
	}
	else
	{
		this.inputList.push(direction);
	}
};

TokenSnake.prototype.animateBite = function(timePassed)
{
	"use strict";

	if (this.biteAnimationState === 'none')
	{
		return;
	}

	this.currentBiteTime += timePassed;

	if (this.biteAnimationState === 'openMouth')
	{       
		this.biteAnimationFrame = Math.floor(this.currentBiteTime / this.biteAnimationTime * 6);
	} 
	else if (this.biteAnimationState === 'closeMouth')
	{
		this.biteAnimationFrame = 6 + Math.floor(this.currentBiteTime / this.biteAnimationTime * 4);

		if (this.currentBiteTime >= this.biteAnimationTime)
		{   
			this.currentBiteTime = 0;
			this.biteAnimationState = 'none';
		}
	}
};

TokenSnake.prototype.playOpenMouthAnimation = function()
{
	"use strict";
	
	if (this.biteAnimationState === 'none')
	{
		this.currentBiteTime = 0;

		this.biteAnimationState = 'openMouth';
	}

};

TokenSnake.prototype.playCloseMouthAnimation = function()
{
	"use strict";

	if (this.biteAnimationState === 'openMouth')
	{
		this.currentBiteTime = 0;
		
		this.biteAnimationState = 'closeMouth';
	}
};

