/////////////////////////////////////////////////////////////
// TokenCrash
//
// This token shows the crash indicator when the snake hits something
//
// Copyright 2014 Tingly Games
// Last Changed: 30-05-2014
/////////////////////////////////////////////////////////////

// The constructor for the TokenCrash game token. 
var TokenCrash = function(x, y) {
	"use strict";
	// Properties used by the engine
	this.depth = -100000;   
	this.visible = true;
	this.active = true;
	this.group = 0;
	//TG.functions.setLayerAndCanvas(this, TG.gameEffectsLayer);
	// Your own properties
	this.x = x;
	this.y = y;
	// Get the correct locations for the settings
	this.generalSettings = TG.settings.game['snake'];
	this.speed = TG.settings.game.collision.speed;
	this.frameTime = TG.settings.game.collision.frameTime;
	this.appearTime = TG.settings.game.collision.appearTime;
	this.lifeTime = 0;
	this.frame = 0;
	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "item", "play"]);
};

// remove the item smoothly
TokenCrash.prototype.removeSmooth = function() { 
	"use strict";
	this.lifeTime = this.maxTime-this.appearTime;
};

// handleEndStep is called each step after processing other events (before draw).
TokenCrash.prototype.handleEndStep = function(timePassed) { 
	"use strict";
	this.lifeTime += timePassed/1000;
	this.frame += (timePassed/1000)/this.frameTime;
	// Remove the crash when its animation is over
	if (Math.floor(this.frame) >= s_crash.number) {
		tbGame.removeToken(this);
	}
	// Adapt the position
	this.y -= this.speed*timePassed/1000;
	// Make sure the canvas is drawn
	//this.canvas.drawTokens = true;
};

// handleDraw is called at the end of a step to draw the token.
TokenCrash.prototype.handleDraw = function() {
	"use strict";
	s_crash.drawSimple(Math.floor(this.frame), this.x, this.y);
};




