// The constructor for the Background game token. 
var Background = function() {
	"use strict";
	// Properties used by the engine
	this.depth = 10000;
	this.layer = 0;
	this.visible = true;
	this.active = true;
	// Your own properties
	this.x = 0;
	this.y = 0;

	this.backgroundCenterX = this.x;
	this.backgroundCenterY = this.y;

	this.snakeOffsetX = Snake.xOff;
	this.snakeOffsetY = Snake.yOff;


	this.shakeChangeTimer = 0.5;
	this.shakeIntensity = 10;
	this.canShake = false;
	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "play", "extra"]);
};

// handleAdd is called when the token is (re-) added to the game. 
Background.prototype.handleAdd = function() {
	"use strict";
};

// handleRemove is called when the token is removed from the game.
Background.prototype.handleRemove = function() {
	"use strict";
};

// handleBeginStep is called each step before processing other events.
Background.prototype.handleBeginStep = function(timePassed) {
	"use strict";
};

// handleTouchDown is called when a touch is started or if a mouse button is pressed.
Background.prototype.handleTouchDown = function(finger, x, y) {
	"use strict";
};

// handleTouchUp is called when a touch is ended or if a mouse button is released.
Background.prototype.handleTouchUp = function(finger, x, y) { 
	"use strict";
};

// handleKeyDown is called if the key with the given keyCode is pressed.
Background.prototype.handleKeyDown = function(keyCode) { 
	"use strict";
};

// handleKeyUp is called if the key with the given keyCode is released.
Background.prototype.handleKeyUp = function(keyCode) { 
	"use strict";
};

// handleAlarm is called if a global alarm is reached.
Background.prototype.handleAlarm = function(alarm) { 
	"use strict";
};

// handleSpecial is called if a special or user-defined event happens.
Background.prototype.handleSpecial = function(id, args) { 
	"use strict";
};

Background.prototype.doScreenShake = function(intensity) {
	"use strict";

	var dx = (Math.random() - 0.5) * intensity;
	var dy = (Math.random() - 0.5) * intensity;

	this.x = this.backgroundCenterX + tgfScale(dx);
	this.y = this.backgroundCenterY + tgfScale(dy);

	Snake.xOff = this.snakeOffsetX + tgfScale(dx);
	Snake.yOff = this.snakeOffsetY + tgfScale(dy);
};

Background.prototype.startShake = function() {
	"use strict";
	this.canShake = true;
	this.snakeOffsetX = Snake.xOff;
	this.snakeOffsetY = Snake.yOff;
};

// handleEndStep is called each step after processing other events (before draw).
Background.prototype.handleEndStep = function(timePassed) { 
	"use strict";
	this.delta = timePassed / 1000;

	if(this.shakeChangeTimer > 0 && this.canShake){
		this.shakeChangeTimer -= this.delta;
		this.doScreenShake(this.shakeIntensity);
	} else {
		this.x = this.backgroundCenterX;
		this.y = this.backgroundCenterY;
		this.canShake = false;
		//Snake.xOff = this.snakeOffsetX;
		//Snake.yOff = this.snakeOffsetY;
	}
};

// handleDraw is called at the end of a step to draw the token.
Background.prototype.handleDraw = function() {
	"use strict";
	s_background.drawSimple(0, this.x, this.y);
};





