// The constructor for the FactScreenTransitionToken game token. 
var FactScreenTransitionToken = function(x, y, onDone, context)
{
	"use strict";
	
	this.alpha          = 1;

	// Properties used by the engine
	this.depth          = 0; 
	this.layer          = 0;
	this.visible        = true;
	this.active         = true;
	
	// Your own properties
	this.x              = x;
	this.y              = y;

	this.onDone         = onDone;
	this.context        = context;
	
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "play"]);

	// Add it to the game engine    
	this._resetFacts();
};

FactScreenTransitionToken.prototype._resetFacts = function()
{
	"use strict";

	this.snakeFacts         = TG.settings.game.factTransitionScreen.facts;  
	this.activeTime         = TG.settings.game.factTransitionScreen.activeTime;
	this.transitionTime     = TG.settings.game.factTransitionScreen.transitionTime;
	this.eligibleForSkip    = TG.settings.game.factTransitionScreen.eligibleForSkip;

	this.isTransitioning    = false;
	this.currentFact        = this._getFact();
};

FactScreenTransitionToken.prototype._getFact = function()
{
	"use strict";
	
	var fullDaysSinceEpoch  = Math.floor(new Date() * 1.1574074074074074e-8); //number of miliseconds since epoch (1-1-1970), divided by the duration of one day.
	var index               = fullDaysSinceEpoch % this.snakeFacts.length;
	return this.snakeFacts[index];
};

// handleAdd is called when the token is (re-) added to the game. 
FactScreenTransitionToken.prototype.handleAdd = function() 
{
	"use strict";
};

// handleRemove is called when the token is removed from the game.
FactScreenTransitionToken.prototype.handleRemove = function() 
{
	"use strict";

	this._resetFacts();
	f_bitdust2.setLineSpacing(0);
	this.onDone.call(this.context);
};

// handleBeginStep is called each step before processing other events.
FactScreenTransitionToken.prototype.handleBeginStep = function(timePassed) 
{
	"use strict";
};

// handleTouchDown is called when a touch is started or if a mouse button is pressed.
FactScreenTransitionToken.prototype.handleTouchDown = function(finger, x, y) 
{
	"use strict";

	if (TG.settings.game.factTransitionScreen.activeTime - this.activeTime > this.eligibleForSkip)
	{ 
		this.isTransitioning    = true;
	}
};

// handleTouchUp is called when a touch is ended or if a mouse button is released.
FactScreenTransitionToken.prototype.handleTouchUp = function(finger, x, y) 
{ 
	"use strict";
};

// handleKeyDown is called if the key with the given keyCode is pressed.
FactScreenTransitionToken.prototype.handleKeyDown = function(keyCode) 
{ 
	"use strict";
};

// handleKeyUp is called if the key with the given keyCode is released.
FactScreenTransitionToken.prototype.handleKeyUp = function(keyCode)
{ 
	"use strict";
};

// handleEndStep is called each step after processing other events (before draw).
FactScreenTransitionToken.prototype.handleEndStep = function(timePassed) 
{ 
	"use strict";

	if (this.isTransitioning)
	{       
		this.alpha -= timePassed / this.transitionTime;
		if (this.alpha <= 0)
		{
			tbGame.removeToken(this);           
		}
	} else
	{
		this.activeTime -= timePassed;
		if (this.activeTime <= 0)
		{
			this.isTransitioning = true;            
		}
	} 
};

// handleDraw is called at the end of a step to draw the token.
FactScreenTransitionToken.prototype.handleDraw = function() 
{
	"use strict";

	s_background.drawAlpha(0, this.x, this.y, this.alpha);
	f_bitdust2.setFontSize(25);

	f_bitdust2.drawAlpha('FACT OF THE DAY', tgfScale(100), tgfScale(150), this.alpha, tgfGraphics.areaWidth - tgfScale(200));
	f_bitdust2.setLineSpacing(10);
	f_bitdust2.setFontSize(20);

	f_bitdust2.drawAlpha(this.currentFact, tgfScale(100), tgfScale(250), this.alpha, tgfGraphics.areaWidth - tgfScale(200));
};




