//******************************************************
//*****    Script Resource: Inheritor
//******************************************************

// *********************************
// CoolGames Builder JavaScript file
// *********************************

function Inherit(A, B)
{
	A.prototype             = Object.create(B.prototype);
	A.prototype.constructor = A;
	A.super                 = B.prototype;
}

//******************************************************
//*****    Script Resource: TimedCollectible
//******************************************************

// ***************************************
// Definition of game token TokenTokenTimedCollectible
// ***************************************

var timedCollectibleIdleState =
{
    'playNormal'    	: 0,
    'playBack'      	: 1,
    'doNothing'     	: 2,
	'playNormalShort'	: 3,
	'playBackShort'		: 4
};

// The constructor for the TokenTimedCollectible game token. 
var TimedCollectible = function(x, y, duration, onEatenCallback, onEatenContext) 
{
	"use strict";
	
	this.duration   = duration;
	this.countDown	= false;

	TimedCollectible.super.constructor.call(this, x, y, onEatenCallback, onEatenContext);	
	TimedCollectible.super.setVariablesAndAddToGame.call(this, collectibleTypes['timedCollectible'], DifficultyController.collectibleScore);
};

Inherit(TimedCollectible, TokenCollectible);

TimedCollectible.prototype.onDurationEnded = function()
{
	"use strict";
	this.animationState = collectibleAnimationState['disappearing'];	
};

TimedCollectible.prototype.getDuration = function(timePassed)
{
	if (this.countDown)
	{
		this.duration -= timePassed;

		if (this.duration <= 0)
		{
			this.onDurationEnded();
		}
	}
	return this.duration;
}

//******************************************************
//*****    Script Resource: AppleCollectible
//******************************************************

// *********************************
// CoolGames Builder JavaScript file
// *********************************

var appleIdleState =
{
    'playNormal'    : 0,
    'playBack'      : 1,
    'doNothing'     : 2
};

var AppleCollectible = function(x, y, onEatenCallback, onEatenContext)
{
    "use strict";

    AppleCollectible.super.constructor.call(this, x, y, onEatenCallback, onEatenContext);
    AppleCollectible.super.setVariablesAndAddToGame.call(this, collectibleTypes['apple'], DifficultyController.appleScore);

    this._numberOfFrames    = 33;
    this._currentFrame      = 0;
    this._currentFrameTime  = 0;
    this._image             = s_apple_appear;

    this._appleIdleState    = appleIdleState['playNormal'];
    this._animationSequence = 0;
}

Inherit(AppleCollectible, TokenCollectible);

AppleCollectible.prototype.handleAppearingState		= function(timePassed) 
{ 
    "use strict";

    this._currentFrameTime += timePassed;
    if (this._currentFrameTime > 10)
    {
        this._currentFrame++;
        this._currentFrameTime = 0;
        if (this._currentFrame >= this._numberOfFrames - 1)
        {
            //switch to idle animation.
            this.animationState     = collectibleAnimationState['idle'];
            this._image             = s_apple_idle;
            this._numberOfFrames    = 15;
            this._currentFrame      = 0;        
        }
    }
};

AppleCollectible.prototype.handlePlayNormal = function(timePassed)
{
    "use strict";

    if (this._currentFrameTime > 33.333333)
    {        
        this._currentFrame++;
        this._currentFrameTime = 0;
        
        if (this._currentFrame === this._numberOfFrames)
        {
            this._appleIdleState    = appleIdleState['playBack'];
            this._currentFrame      = 13;
        }
    }
};

AppleCollectible.prototype.handlePlayBack = function(timePassed)
{
    "use strict";

    if (this._currentFrameTime > 33.333333)
    {        
        this._currentFrame--;
        this._currentFrameTime = 0;
        
        if (this._currentFrame === 0)
        {
            this._animationSequence ++
            if (this._animationSequence === 2)
            {
                this._appleIdleState    = appleIdleState['doNothing'];
                this._animationSequence = 0;
            } else this._appleIdleState = appleIdleState['playNormal'];
        }
    }
};

AppleCollectible.prototype.handleIdleState = function(timePassed) 
{ 
    "use strict";

    this._currentFrameTime += timePassed;

    switch (this._appleIdleState)
    {
        case appleIdleState['playNormal']:
            this.handlePlayNormal(timePassed);
            break;
        case appleIdleState['playBack']:
            this.handlePlayBack(timePassed);
            break;
        case appleIdleState['doNothing']:
            if (this._currentFrameTime >= 2000)
            {
                this._currentFrameTime  = 0;
                this._appleIdleState    = appleIdleState['playNormal'];
            }
            break;
    }
};

AppleCollectible.prototype.handleDraw = function() 
{
	"use strict";

    this._image.drawExt(this._currentFrame, this.x, this.y, 1, 1, 0, 1);
};
