// The constructor for the CollectibleController game token. 
var CollectibleController = function()
{
	"use strict";
	// Properties used by the engine
	this.depth      = 0; 
	this.layer      = 0;
	this.visible    = true;
	this.active     = true;

	this.uiCollectables = [s_timed_collectible_snail, s_timed_collectible_mouse, s_timed_collectible_bird, s_timed_collectible_bug, s_timed_collectible_phone];
	this.collected = 0;
	
	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "play", "extra"]);

	this.applesCollectedSinceLastTimedCollectible = 0; //the amount of apples that the player has collected since they last collected a timed collectible.
	this.timedCollectible = undefined;
	this.applesToCollectInOrderToSpawnTimedCollectible  = 0;

	this.eggSpawnChance     = 0;
	this.totalApplesEaten   = 0;
	this.hasPickedupEgg     = false;
	this.hasEggSpawned      = false;

	this.bottomCap          = TG.settings.game.eggSpawning[SkinController.skin].bottomCap;
	this.topCap             = TG.settings.game.eggSpawning[SkinController.skin].topCap;
	this.chanceIncrement    = TG.settings.game.eggSpawning[SkinController.skin].chanceIncrement;
	this.collectableScoreIncrease = TG.settings.game.collectableScoreIncrease.score;
	this.collectableTimeDicrease = TG.settings.game.collectableTimeDicrease.time;

	this.ranks              = TG.settings.game.levelEnd.ranks;
	this.currentRank        = 0;

	this.textFloaters       = new TextFloaterController();

	this.date = new Date();
};

CollectibleController.prototype.addUiElements = function()
{
	"use strict";
	this.eggCollectibleIcon = Snake.ui.addUiComponent(tgfComponents.Picture,
	{
		image   : s_egg,
		x       : tgfScale(350),
		y       : tgfScale(45)
	});

	this.timedCollectibleTimer = Snake.ui.addUiComponent(tgfComponents.Label, 
	{
		font    : {fontFace: f_bitdust2.fontFace, fontSize: 38, fillColor: "#b0e203", baseline: "middle"},
		y       : tgfScale(40),
		x       : tgfScale(770),
		text    : "0.0",
		align   : "left",
		width   : tgfScale(500), height: tgfScale(500)
	});

	this.timedCollectibleIcon   = Snake.ui.addUiComponent(tgfComponents.Picture,
	{
		x       : tgfScale(490),
		y       : tgfScale(40),
		image   : s_timed_collectible_bug
	});
};

CollectibleController.prototype.init = function()
{
	"use strict";

	this._setTimedCollectibleUiVisibility(false);

	this.eggCollectibleIcon.isVisible = false;

	this._setRandomTimedCollectibleSpawnTime();

	this.spawnApple();
};

CollectibleController.prototype._setRandomTimedCollectibleSpawnTime = function()
{
	"use strict";

	var min = DifficultyController.collectibleMinApples;
	var max = DifficultyController.collectibleMaxApples;

	this.applesToCollectInOrderToSpawnTimedCollectible = this.randomRange(min, max);
	this.applesCollectedSinceLastTimedCollectible = 0;
};

CollectibleController.prototype.randomRange = function(min, max)
{
	"use strict";
	
	return Math.floor(Math.random() * (max - min + 1) + min);
};

CollectibleController.prototype._setTimedCollectibleUiVisibility    = function(value)
{
	"use strict";
	
	this.timedCollectibleTimer.isVisible = value;   
	this.timedCollectibleIcon.isVisible = value;
};

CollectibleController.prototype.spawnApple = function()
{
	"use strict";
	
	var pos = Snake.getCollectibleLocation();
	if (pos)
	{
		new AppleCollectible(pos.x, pos.y, this.onCollectibleEaten, this);
	}
};

CollectibleController.prototype._checkRank = function()
{
	"use strict";

	if (this.currentRank  === this.ranks.length - 1)
		return;

	if (Snake.score.valueNew >= this.ranks[this.currentRank + 1].threshold)
	{
		if (this.currentRank < this.ranks.length)
			this.currentRank++;
		
		this.textFloaters.addFloater('RANK UP!', 48, tgfGraphics.areaWidth / 2, tgfGraphics.areaWidth / 2);
	}
};

CollectibleController.prototype._trySpawnTimedCollectible = function()
{
	"use strict";

	if (this.timedCollectible === undefined)
	{
		if (this.applesCollectedSinceLastTimedCollectible === this.applesToCollectInOrderToSpawnTimedCollectible)
		{
			var pos                         = Snake.getCollectibleLocation();
			if (pos)
			{
				DifficultyController.collectibleScore = DifficultyController.collectibleStartScore + (this.collectableScoreIncrease * this.collected);
				DifficultyController.collectibleDuration = DifficultyController.collectibleStartDuration - (this.collectableTimeDicrease * this.collected);
				this.timedCollectible           = new TimedCollectible_Bug(pos.x, pos.y, DifficultyController.collectibleDuration, this.onCollectibleEaten, this, this.collected);

				console.log("Collectable Score: " + DifficultyController.collectibleScore);

				this.timedCollectibleIcon.image = this.uiCollectables[this.collected];
				tbAudio.play(a_collectible_appear);
				
				this._setTimedCollectibleUiVisibility(true);
			}
		} else this.applesCollectedSinceLastTimedCollectible++;
	}
};

CollectibleController.prototype._trySpawnEgg = function()
{
	"use strict";

	this.eggSpawnChance += this.chanceIncrement;

	if(TG.game.saveFile["eggsCollected"] > SkinController.skin){
		return;
	}

	if (!this.hasPickedupEgg && !this.hasEggSpawned && this.totalApplesEaten > this.bottomCap)
	{
		var percentage = this.eggSpawnChance / 100;

		if(Math.random() < percentage || this.totalApplesEaten > this.topCap)
		{
			for(var i = 0; i < 30; i++){
				if(TG.game.saveFile["snakes"][i] && !TG.game.saveFile["snakes"][i]["unlocked"] && TG.game.saveFile["snakes"][i]["foundEgg"] && TG.game.saveFile["snakes"][i]["timestamp"] > 0){
					return;
				}
			}

			var pos = Snake.getCollectibleLocation();
			if (pos)
			{
				this.hasEggSpawned = true;

				new EggCollectible(pos.x, pos.y, this.onCollectibleEaten, this);

				tbAudio.play(a_egg_appear);
			}
		}
	}
};

CollectibleController.prototype.setDurationText = function(duration)
{
	"use strict";
	var dValue = Math.max(0, duration).toString();
	while (dValue.length < 4) 
	{
		dValue = "0" + dValue;
	}
	
	this.timedCollectibleTimer.text = dValue[0] + '.' + dValue[1];
	this.timedCollectibleTimer.recreate();
};

CollectibleController.prototype.onCollectibleEaten = function(collectible)
{
	"use strict";
	
	this.textFloaters.addFloater(collectible.score.toString(), 34, collectible.x, collectible.y - 25);
	this._checkRank();
	switch (collectible.collectibleType)
	{
		case collectibleTypes['apple']:         
			this.totalApplesEaten++;
			this.spawnApple();
			this._trySpawnTimedCollectible();
			this._trySpawnEgg();
			tbAudio.play(a_apple_eat);
			break;
		case collectibleTypes['timedCollectible']:

			if(this.collected + 1 < this.uiCollectables.length){
				this.collected++;
			}

			this.removeTimedCollectible(true);
			tbAudio.play(a_collectible_eat);
			break;
		case collectibleTypes['egg']:
			this.textFloaters.addFloater('NEW EGG!', 48, tgfGraphics.areaWidth / 2, tgfGraphics.areaWidth / 2);
			this.eggCollectibleIcon.isVisible   = true;
			this.hasPickedupEgg                 = true;
			this.eggCollected();
			tbAudio.play(a_egg_collect);
			break;
	}

	Vibration.eat();
	Snake.snakeToken.addCollectible(collectible);
};

CollectibleController.prototype.eggCollected = function() {
	"use strict";
	TG.game.saveFile["eggsCollected"]++;

	if(TG.game.saveFile["snakes"][TG.game.saveFile["eggsCollected"]]){
		TG.game.saveFile["snakes"][TG.game.saveFile["eggsCollected"]]["timestamp"] = this.date.getTime();
	}

	TG.game.saveData();
};

// handleRemove is called when the token is removed from the game.
CollectibleController.prototype.removeTimedCollectible = function(didEat)
{
	"use strict";

	this.timedCollectible   = undefined;
	this._setTimedCollectibleUiVisibility(false);
	this._setRandomTimedCollectibleSpawnTime();
	if(!didEat){
		this.collected = 0;
		DifficultyController.collectibleScore = DifficultyController.collectibleStartScore;
		DifficultyController.collectibleDuration = DifficultyController.collectibleStartDuration;
		tbAudio.play(a_collectible_disappear);
	}
};

