var TimedCollectible_Bug = function(x, y, duration, onEatenCallback, onEatenContext, type)
{
    TimedCollectible_Bug.super.constructor.call(this, x, y, duration, onEatenCallback, onEatenContext, type);

    this.collectables = [
        {
            appear: s_snail_appear,
            idle: s_snail_idle,
            disappear: s_snail_hide
        },
        {
            appear: s_mouse_appear,
            idle: s_mouse_idle,
            disappear: s_mouse_hide
        },
        {
            appear: s_bird_appear,
            idle: s_bird_idle,
            disappear: s_bird_hide
        },
        {
            appear: s_bug_appear,
            idle: s_bug_idle,
            disappear: s_bug_hide
        },
        {
            appear: s_phone_appear,
            idle: s_phone_idle,
            disappear: s_phone_hide
        }
    ];

    this.type = type;
    this._numberOfFrames    = this.collectables[this.type].appear.number + 1; //20;
    this._currentFrame      = 0;
    this._currentFrameTime  = 0;
    this._image             = this.collectables[this.type].appear; //s_bug_appear;

    this._collectibleState  = timedCollectibleIdleState['playNormal'];
    this._animationSequence = 0;
}

Inherit(TimedCollectible_Bug, TimedCollectible);

TimedCollectible_Bug.prototype.handleAppearingState = function(timePassed)
{
     "use strict";

    this._currentFrameTime += timePassed;
    if (this._currentFrameTime > 10)
    {
        this._currentFrame++;
        this._currentFrameTime = 0;
        if (this._currentFrame >= this._numberOfFrames - 1)
        {
            //switch to idle animation.
            this.animationState     = collectibleAnimationState['idle'];
            this._image             = this.collectables[this.type].idle; //s_bug_idle;
            this._numberOfFrames    = this.collectables[this.type].idle.number; //12;
            this._currentFrame      = 0;
            this.countDown          = true;        
        }
    }
};

TimedCollectible_Bug.prototype.handlePlayNormal = function(timePassed)
{
    "use strict";

    if (this._currentFrameTime > 33.333333)
    {        
        this._currentFrame++;
        this._currentFrameTime = 0;
        
        if (this._currentFrame === this._numberOfFrames)
        {
            this._collectibleState      = timedCollectibleIdleState['playBack'];
            this._currentFrame          = this.collectables[this.type].idle.number - 2;//12;
        }
    }
};

TimedCollectible_Bug.prototype.handlePlayBack = function(timePassed)
{
    "use strict";

    if (this._currentFrameTime > 33.333333)
    {        
        this._currentFrame--;
        this._currentFrameTime = 0;
        
        if (this._currentFrame === 0)
        {
            this._animationSequence++;
            if (this._animationSequence === 2)
            {
                this._collectibleState      = timedCollectibleIdleState['doNothing'];
                this._animationSequence     = 0;
            } else {
                this._collectibleState   = timedCollectibleIdleState['playNormal'];
            }
        }
    }
};

TimedCollectible_Bug.prototype.onDurationEnded = function()
{
	"use strict";

    TimedCollectible_Bug.super.onDurationEnded.call(this);

    this._currentFrameTime  = 0;

    this._currentFrame      = 0;

    this._image             = this.collectables[this.type].disappear; //s_bug_disappear;
};

TimedCollectible_Bug.prototype.handleDisappearingState = function(timePassed)
{
    "use strict";

    this._currentFrameTime += timePassed;

    if (this._currentFrameTime > 33.333333)
    {
        this._currentFrame++;
        this._currentFrameTime = 0;

        if (this._currentFrame === this.collectables[this.type].disappear.number)
        {
            tbGame.removeToken(this);
        }
    }
};

TimedCollectible_Bug.prototype.handleIdleState = function(timePassed) 
{ 
    "use strict";

    this._currentFrameTime += timePassed;

    switch (this._collectibleState)
    {
        case timedCollectibleIdleState['playNormal']:
            this.handlePlayNormal(timePassed);
            break;
        case timedCollectibleIdleState['playBack']:
            this.handlePlayBack(timePassed);
            break;
        case timedCollectibleIdleState['doNothing']:
            if (this._currentFrameTime >= 2000)
            {
                this._currentFrameTime  = 0;
                this._collectibleState  = timedCollectibleIdleState['playNormal'];
            }
            break;
    }
}

// handleDraw is called at the end of a step to draw the token.
TimedCollectible_Bug.prototype.handleDraw = function()
{
	"use strict";

    this._image.drawExt(this._currentFrame, this.x, this.y, 1, 1, 0, 1);
};
