// The constructor for the TextFloaterController game token. 
var TextFloaterController = function() 
{
	"use strict";
	// Properties used by the engine
	this.depth      = -10000; 
	this.layer      = -1;
	this.visible    = true;
	this.active     = true;
	// Your own properties
	
	// Add it to the game engine
	tbGame.addToken(this);
	tbGame.addTokenTags(this, ["game", "floaters", "play", "extra"]);

	this.alphaDuration  = TG.settings.game.floaters.alphaDuration;
	this.floatDuration  = TG.settings.game.floaters.floatDuration;
	this.moveUpSpeed    = TG.settings.game.floaters.moveUpSpeed;

	this.alphaReduction = this.alphaDuration / 1000;
	this.floatReduction = this.floatDuration / 1000;

	//floaters have a text, position, alpha, size.
	this.floaters   = [];
};

TextFloaterController.prototype.addFloater = function(text, size, x, y)
{
	"use strict";

	this.floaters.push
	({
		text    : text,
		size    : size,
		alpha   : 1,
		float   : 1,
		x       : x,
		y       : y
	});
};

// handleEndStep is called each step after processing other events (before draw).
TextFloaterController.prototype.handleEndStep = function(timePassed) 
{ 
	"use strict";

	for (var i = this.floaters.length - 1; i >= 0; --i)
	{
		var floater     = this.floaters[i];
		floater.y       -= this.moveUpSpeed;

		if (floater.float > 0)
		{
			floater.float   -= this.floatReduction * timePassed;
		} else
		{
			floater.alpha   -= this.alphaReduction * timePassed;
		}

		if (floater.alpha <= 0)
		{
			this.floaters.splice(i, 1);
		}
	}
};

// handleDraw is called at the end of a step to draw the token.
TextFloaterController.prototype.handleDraw = function() 
{
	"use strict";

	for (var i = 0; i < this.floaters.length; ++i)
	{
		var floater     = this.floaters[i];
		f_bitdust2.setFontSize(floater.size);
		f_bitdust2.setAlign('center');

		f_bitdust2.setFillColor('#b0e203');
		f_bitdust2.drawAlpha(floater.text, tgfScale(floater.x), tgfScale(floater.y + 1), floater.alpha, tgfGraphics.areaWidth - tgfScale(200));

		f_bitdust2.setFillColor('#23321a');
		f_bitdust2.drawAlpha(floater.text, tgfScale(floater.x), tgfScale(floater.y - 1), floater.alpha, tgfGraphics.areaWidth - tgfScale(200));

		f_bitdust2.setFillColor('#688601');
		f_bitdust2.drawAlpha(floater.text, tgfScale(floater.x), tgfScale(floater.y), floater.alpha, tgfGraphics.areaWidth - tgfScale(200));
	}
};






