// Processing required when preparing the dialog for use
tgfDialogs.GameEnd.prototype.doPrepare = function() 
{
    "use strict";
    var self = this, rank = this.ranks[0], rankImage = this.rankImages[0], noRank = 1;

    tgfDialogs.GameEnd.uber.doPrepare.call(this);

    
    for (var i = this.ranks.length - 1; i >= 0; --i)
    {
        rank        = this.ranks[i];
        rankImage   = this.rankImages[i];
        noRank      = i + 1;
        if (this.points >= this.ranks[i].threshold)
        {
            break;
        }
    }

    this.snakeBadge = new tgfComponents.Picture({
        image: this.snakeUsed[SkinController.skin],
        x: tgfScale(-173),
        y: tgfScale(-110)
    });

    this.container.addComponent(this.snakeBadge);

    this.snakeNameComponent  = new tgfComponents.Label
    ({
        font: {fontFace: f_bitdust2.fontFace, fontSize: 20, fillColor: "#9ac503", baseline: "middle", align: "center"},
        x: tgfScale(-173), y: tgfScale(-215), width: tgfScale(500), height: tgfScale(500),
        text: DifficultyController.snakeName[DifficultyController.levelIndex]
    });

    this.container.addComponent(this.snakeNameComponent);

    this.speedNumberComponent  = new tgfComponents.Label
    ({
        font: {fontFace: f_bitdust2.fontFace, fontSize: 20, fillColor: "#9ac503", baseline: "middle", align: "center"},
        x: tgfScale(-173), y: tgfScale(-5), width: tgfScale(500), height: tgfScale(500),
        text: "Speed " + (DifficultyController.selectedSpeed + 1)
    });

    this.container.addComponent(this.speedNumberComponent);

    var score = this.points.toString();
    score = score.replace(/([0-9]+?)([0-9]{3})(?=.*?\.|$)/mg, "$1,$2");

    this.scoreTitleComponent = new tgfComponents.Label
    ({
        font: {fontFace: f_bitdust2.fontFace, fontSize: 20, fillColor: "#202e17", baseline: "middle", align: "center"},
        x: tgfScale(20), y: tgfScale(-125), width: tgfScale(500), height: tgfScale(500),
        text: "SCORE"
    });

    this.container.addComponent(this.scoreTitleComponent);

    this.scoreComponent = new tgfComponents.Label
    ({
        font: {fontFace: f_bitdust2.fontFace, fontSize: 50, fillColor: "#202e17", baseline: "middle", align: "center"},
        x: tgfScale(22), y: tgfScale(-90), width: tgfScale(500), height: tgfScale(500),
        text: score
    });

    this.container.addComponent(this.scoreComponent);

    this.playButton = new tgfComponents.Button ({
        image: button_playagain,
        y: tgfScale(310),
        // text: "PLAY AGAIN",
        // fontUp :    {fontFace: f_bitdust2.fontFace, fontSize: 48, fillColor: "#b0e203", baseline: "middle", align: "center"},
        onClick: function(){
            gameController.stopPlay();
            self.hide();
            self.doFree();
        }
    });

    this.container.addComponent(this.playButton);

    // Add the additional components
    for (var i = 0; i < this.components.length; i += 1)
    {
        this.container.addComponent(this.components[i]);
    }
};

