tgfDialogs.GameStart.prototype.onPlayPressed = function() 
{
    "use strict";
    // Deactivate dialog
    this.deactivate();

    this.container.startSubEffect(1);

    DifficultyController.setup(this.currentDifficulty, this.selectedSnake, this.selectedSpeed, this.snakeNames);

    SkinController.setup(this.selectedSnake);

    this.callback.call(this.context, this.selectedSkin);

    this.saveFile();

    var _date = new Date();

    this.context.timeStart = _date.getTime();
};

tgfDialogs.GameStart.prototype.playDisappear = function(){
    "use strict";
    this.deactivate();
    this.container.startSubEffect(1);
};

tgfDialogs.GameStart.prototype.onClickMute = function(){
    tgfSettings.game.muted = tgfSettings.game.muted ? false : true;
    if(tgfSettings.game.muted){
        this.buttonSoundOff.isVisible = true;
        this.buttonSoundOn.isVisible = false;
        tgfAudio.muteEffects();
        tgfAudio.muteMusic();                    
    }else{
        this.buttonSoundOff.isVisible = false;
        this.buttonSoundOn.isVisible = true;
        tgfAudio.unmuteEffects();
        tgfAudio.unmuteMusic();
    }
}

tgfDialogs.GameStart.prototype.onSpeedSelected = function(comp){
    "use strict";
    //if(this.tempLock){
    //    return;
    //}

    for(var i = 0; i < 3; ++i)
    {
        var id  = 'speed_' + i.toString();
        this.speedButtonsActive[i].isVisible    = (comp.id === id);
        this.speedButtonsInactive[i].isVisible  = (comp.id !== id);
    }

    switch (comp.id)
    {
        case 'speed_0':
            this.currentDifficulty  = this.difficultySettings.min;
            this.selectedSpeed = 0;
            //DifficultyController.controllerOption = 0;
            break;
        case 'speed_1':
            this.currentDifficulty  = this.difficultySettings.med;
            this.selectedSpeed = 1;
            //DifficultyController.controllerOption = 1;
            break;
        case 'speed_2':
            this.currentDifficulty  = this.difficultySettings.max;
            this.selectedSpeed = 2;
            //DifficultyController.controllerOption = 2;
            break;
    }
};

tgfDialogs.GameStart.prototype.createSoon = function(){
    "use strict";

    var container = new tgfComponents.Container({
        effects: [{ effect: "show", duration: 99999999 }, this.effectAppear]
    });

    var _snakeIcon = new tgfComponents.Picture({
        image: this.snakeSoonImage, y: tgfScale(-270)
    });

    container.addComponent(_snakeIcon);
    return container;
};

tgfDialogs.GameStart.prototype.createSnake = function(index, properties){
    "use strict";

    var container = new tgfComponents.Container({
        effects: [{ effect: "show", duration: 99999999 }, this.effectAppear],
        id: index
    });

    var _snakeIcon = new tgfComponents.Picture({
        image: this.snakeIcons[index], y: tgfScale(-290)
    });

    var _snakeName = new tgfComponents.Label({
        font: this.fontSelect,
        text: this.snakeNames[index],
        y: tgfScale(-100)
    });

    container.addComponent(_snakeIcon);
    container.addComponent(_snakeName);

    return container;
};

tgfDialogs.GameStart.prototype.createHatch = function(id){
    "use strict";
    var self = this;

    // self.tempLock = true;

    var _snakeEgg = new tgfComponents.Animation({
        animationImage: s_egg_unlocking_animation, y: tgfScale(-290),
        loopAnimation: false,
        didPress: false,
        id: -1,
        index: id,
        onClick: function(comp){
            if(!comp.didPress){
                if(self.currentEggHatched > -1){
                    self.currentEggHatched = -1;
                }
                comp.animationSpeed = 1.5;
                comp.startAnimation = true;
                comp.didPress = true;
            }
        },
        onAnimationComplete: function(comp){
            self.snakeCollection["snakes"][comp.index]["hatch"] = true;
            self.showCollection(comp.index);
            //unlock functionallity
            // self.tempLock = false;
            comp.hide();
        },
        onFrameChange: function(imageIndex){
            if(self.sounds[imageIndex]){
                tbAudio.play(self.sounds[imageIndex]);
            }
        }
    });

    this.container.addComponent(_snakeEgg);
    _snakeEgg.show();
    _snakeEgg.activate();
};

tgfDialogs.GameStart.prototype.createEgg = function(index, properties){
    "use strict";
    var self = this;
    var _eggImage = egg_locked;

    var container = new tgfComponents.Container({
        effects: [{ effect: "show", duration: 99999999 }, this.effectAppear],
        id: index
    });

    if(index > 5){
        _eggImage = s_new_egg_locked;
    }

    var _snakeIcon = new tgfComponents.Picture({
        image: _eggImage, y: tgfScale(-290)
    });

    var _snakeName = new tgfComponents.Label({
        font: this.fontSelect,
        text: this.hiddenTitle,
        y: tgfScale(-100)
    });

    var tapLabel = new tgfComponents.Label({
        text: "",
        y: tgfScale(-301),
        font: {fontFace: f_bitdust2.fontFace, fontSize: 26, fillColor: "#b0e203", baseline: "middle", align: "center"},
        effects: [{effect: tgfEffects.popElastic, duration: 4, startScaleX: 1, endScaleX: 1.25, startScaleY: 1, endScaleY: 0.9, easeArgument: 1, name: "elastic"}],
        onSubEffectEnd: function(component ,effect){
            if(effect.name === "elastic"){component.startSubEffect(0);}
        }
    });

    var timeLeft = (((properties["hours"] * 60) * 60) * 1000);

    var curTime = timeLeft - (properties["curStamp"] - properties["timestamp"]);

    if(curTime < 0){
        curTime = 0;
    }

    var _timer = new tgfComponents.UiValue({
        tapLabel: tapLabel,
        id: index,
        width: tgfScale(600),
        height: tgfScale(200),
        y: tgfScale(-270),
        valueFont: {fontFace: f_bitdust2.fontFace, fontSize: 36, fillColor: "#b0e203"},
        valueType: "time",
        valueStart: (curTime / 1000),
        valueSeparator: ":",
        alwaysShowHours: true,
        alwaysShowMinutes: true,
        accurateTimingEnabled: true,
        endTime: curTime + tbGame.lastTime,
        done: false,
        onValueChangeEnd: function(comp, value){
            if(value === 0){
                self.tempLock = true;
                comp.done = true;
                comp.tapLabel.text = "TAP\nTO OPEN\nTHIS EGG";
                comp.tapLabel.recreate();
                comp.hide();
                self.unlockEgg(comp.id);
            }
        }
    });

    if(properties["foundEgg"]){
        _snakeIcon.image = egg_harching;
        _snakeName.text = "WAIT TO OPEN\n   THIS EGG";
    }
    container.addComponent(_snakeIcon);

    container.addComponent(_snakeName);

    if(properties["foundEgg"]){
        container.addComponent(_timer);
        if(curTime <= 10000 && !properties["hatch"]){
            this.selectedSnake = index;
            _snakeName.text = "TAP TO OPEN\n   THIS EGG";
            _snakeName.recreate();
        }
    } else if(properties["foundEgg"] && properties["unlocked"] && !properties["hatch"]) {
        tapLabel.text = "TAP\nTO OPEN\nTHIS EGG";
        _snakeName.text = "TAP TO OPEN\n   THIS EGG";
        _snakeName.recreate();
        this.selectedSnake = index;
        _timer.hide();
    }

    container.addComponent(tapLabel);

    return {
        container: container,
        timer: _timer
    };
};

tgfDialogs.GameStart.prototype.unlockEgg = function(index){
    "use strict";
    if(!this.snakeCollection["snakes"][index]["unlocked"]){
        //TODO more stuff to show player tap tap hatch (polish)
        this.snakeCollection["snakes"][index]["unlocked"] = true;

        this.currentEggHatched = index;

        this.createHatch(index);
    }
};

tgfDialogs.GameStart.prototype.nextSkin = function(){
    "use strict";
    if(this.selectedSnake + 1 === this.snakeIcons.length){
        this.selectedSnake = this.snakeIcons.length;
        this.nextButton.hide();
        this.showCollection(this.selectedSnake);
    } else {
        this.selectedSnake++;
        this.previousButton.show();
        this.previousButton.activate();
        this.showCollection(this.selectedSnake);
    }

    //console.log("Next: " + this.selectedSnake);
};

tgfDialogs.GameStart.prototype.previousSkin = function(){
    "use strict";
    if(this.selectedSnake - 1 === 0){
        this.selectedSnake = 0;
        this.previousButton.hide();
        this.showCollection(this.selectedSnake);
    } else {
        this.selectedSnake--;
        this.nextButton.show();
        this.nextButton.activate();
        this.showCollection(this.selectedSnake);
    }

    //console.log("Prev: " + this.selectedSnake);
};

tgfDialogs.GameStart.prototype.hideCollection = function () {
    "use strict";
    for(var i = 0; i < this.activeCollection.length; i++){
        this.activeCollection[i].hide();
        this.inactiveCollection[i].hide();
    }
};

tgfDialogs.GameStart.prototype.showCollection = function (index) {
    "use strict";
    this.hideCollection();
    if(this.snakeCollection["snakes"][index]){
        if(this.hack || (this.snakeCollection["snakes"][index]["unlocked"] && this.snakeCollection["snakes"][index]["hatch"] && this.activeCollection[index])){
            this.activeCollection[index].show();
            this.activeCollection[index].startSubEffect(1);
        } else {
            this.inactiveCollection[index].show();
            this.inactiveCollection[index].startSubEffect(1);
            // if(this.timerCollection[index].done  || this.timerCollection[index].value === 0){
            //     this.timerCollection[index].hide();
            // }
        }
    } else {
        this.activeCollection[index].show();
        this.activeCollection[index].startSubEffect(1);
    }

    this.checkLocked(index);
    this.enableTimers(index);
};

tgfDialogs.GameStart.prototype.checkLocked = function(index) {
    "use strict";
    if(this.snakeCollection["snakes"][index]){
        if(this.hack || (this.snakeCollection["snakes"][index]["unlocked"] && this.snakeCollection["snakes"][index]["hatch"])){
            this.lockPlay = false;
            this.customStartButtonComponent.image =  button_play;
        } else {
            this.lockPlay = true;
            this.customStartButtonComponent.image = button_play_inactive;
        }
    } else {
        this.lockPlay = true;
        this.customStartButtonComponent.image = button_play_inactive;
    }

    this.customStartButtonComponent.recreate();
};

tgfDialogs.GameStart.prototype.enableTimers = function(index){
    "use strict";

    if(this.hack){
        return;
    }

    if(this.snakeCollection["snakes"][index] && !this.snakeCollection["snakes"][index]["unlocked"] && this.inactiveCollection && this.inactiveCollection[index] && this.inactiveCollection[index].activate){
        this.inactiveCollection[index].activate();
    }
};

tgfDialogs.GameStart.prototype.saveFile = function(){
    "use strict";
    this.snakeCollection["skinSelection"] = this.selectedSnake;
    this.snakeCollection["speedSelection"] = this.selectedSpeed;

    // if(tgfHooks.saveExtraData){
    //     tgfHooks.saveExtraData(this.snakeCollection);
    // }
    PlayerDataService.savePlayerData([{
        identifier: "saveState",
        data: this.snakeCollection
    }]);

    this.updateSave();
};

tgfDialogs.GameStart.prototype.updateSave = function(){
    "use strict";
    // if(tgfHooks.updateExtraData){
    //     tgfHooks.updateExtraData(this.snakeCollection);
    // }

    if(this.onUpdate){
        this.onUpdate(this.snakeCollection);
    }
};

tgfDialogs.GameStart.prototype.checkEggCollection = function(){
    "use strict";
    for(var i = 0; i < this.snakeCollection["eggsCollected"] + 1; i++){
        this.snakeCollection["snakes"][i]["foundEgg"] = true;
    }
};

tgfDialogs.GameStart.prototype.updateStamps = function(stamp){
    "use strict";
    for(var i = 0; i < this.snakeIcons.length; i++){
        this.snakeCollection["snakes"][i]["curStamp"] = stamp;
    }
};

// ***************************************
// Preparing and showing
// ***************************************

// Processing required when preparing the dialog for use
tgfDialogs.GameStart.prototype.doPrepare = function() 
{
    "use strict";
    var context = this;
    this.date = new Date();
    this.updateStamps(this.date.getTime());

    this.checkEggCollection();

    //SETTING THE PROPS
    this.selectedSnake = this.snakeCollection["skinSelection"];
    this.selectedSpeed = this.snakeCollection["speedSelection"];

    this.container = new tgfComponents.Container({
        x: tgfGraphics.areaWidth / 2,
        y: tgfGraphics.areaHeight / 2,
        effects: [{ effect: "show", duration: 99999999 }, this.effectDisappear],
        onEffectEnd: function(comp){
            context.hide();
        }
    });

    this.bg = new tgfComponents.Picture({
        image: s_startscreen_background
    });

    this.container.addComponent(this.bg);

    this.labelSelectSkin = new tgfComponents.Label({
        font: this.fontSelect,
        text: "-SELECT SNAKE-",
        y: tgfScale(-500)
    });

    this.container.addComponent(this.labelSelectSkin);

    for(var i = 0; i < this.snakeIcons.length; i++){
        var scrollContainer = new tgfComponents.Container({
            effects: [{ effect: "show", duration: 99999999 }, this.effectAppear]
        });

        var _active = this.createSnake(i, this.snakeCollection["snakes"][i]);
        this.activeCollection.push(_active);

        var _inactive = this.createEgg(i, this.snakeCollection["snakes"][i]);
        this.inactiveCollection.push(_inactive.container);
        this.timerCollection.push(_inactive.timer);

        scrollContainer.addComponent(_active);
        scrollContainer.addComponent(_inactive);
    }

    var createSoon = this.createSoon();

    this.activeCollection.push(createSoon);
    this.inactiveCollection.push(createSoon);

    this.previousButton = new tgfComponents.Button({
        image: s_button_previous_skin,
        x: tgfScale(-230),
        y: tgfScale(-290),
        onClick: function(comp){
            //if(!context.tempLock){
                context.previousSkin();
            //}
        }
    });

    this.container.addComponent(this.previousButton);

    this.nextButton = new tgfComponents.Button({
        image: s_button_next_skin,
        x: tgfScale(230),
        y: tgfScale(-290),
        onClick: function(comp){
            //if(!context.tempLock){
                context.nextSkin();
            //}
        }
    });

    this.container.addComponent(this.nextButton);

    for(var y = 0; y < this.activeCollection.length; y++){
        this.container.addComponent(this.activeCollection[y]);
        this.container.addComponent(this.inactiveCollection[y]);
    }

    this.labelSelect = new tgfComponents.Label({
        font: this.fontSelect,
        text: "-SELECT SPEED-",
        y: tgfScale(-30)
    });

    this.container.addComponent(this.labelSelect);

    var sound_button_on = new tgfComponents.Button({
        image   : s_button_sound_on, x : tgfScale(tgfGraphics.areaWidth / 2) - tgfScale(50), y: -tgfScale(tgfGraphics.areaHeight / 2) + tgfScale(80),
        id      : 'sound_button_on', 
        marginTop : tgfScale(0),
        onClick: function(){context.onClickMute()},
    });
    this.buttonSoundOn = sound_button_on;
    this.__components.push(sound_button_on);

    var sound_button_off = new tgfComponents.Button({
        image   : s_button_sound_off, x : tgfScale(tgfGraphics.areaWidth / 2) - tgfScale(50), y: -tgfScale(tgfGraphics.areaHeight / 2) + tgfScale(80),
        id      : 'sound_button_off', 
        marginTop : tgfScale(0),
        onClick: function(){context.onClickMute()},
    });
    this.buttonSoundOff = sound_button_off;
    this.__components.push(sound_button_off);

    for (var i = 0; i < 3; ++i)
    {
        var snakeSpeedSelection    = new tgfComponents.Button
        ({
            image   : s_button_speed_deselect, x : tgfScale(190 * i - 190), y: tgfScale(65),
            id      : 'speed_' + i.toString(), text : (i + 1).toString(),
            fontUp  : {fontFace: f_bitdust2.fontFace, fontSize: 50, fillColor: "#b0e203", baseline: "middle", align: "center"},
            marginTop : tgfScale(0),
            onClick : function(comp)
            {                
                context.onSpeedSelected(comp);
            }
        });
        this.speedButtonsInactive.push(snakeSpeedSelection);
        this.__components.push(snakeSpeedSelection);
    }

    for (var i = 0; i < 3; ++i)
    {
        var snakeSpeedSelection    = new tgfComponents.Button
        ({
            image   : s_button_speed_select, x : tgfScale(190 * i - 190), y: tgfScale(65),
            id      : 'speed_' + i.toString(), text    : (i + 1).toString(),            
            fontUp  : {fontFace: f_bitdust2.fontFace, fontSize: 50, fillColor: "#23321a", baseline: "middle", align: "center"},
            marginTop : tgfScale(0)
        });
        this.speedButtonsActive.push(snakeSpeedSelection);
        this.__components.push(snakeSpeedSelection);
    }

    this.customStartButtonComponent = new tgfComponents.Button
    ({
        image :     button_play, x: tgfScale(0), y: tgfScale(350),
        // fontUp :    {fontFace: f_bitdust2.fontFace, fontSize: 48, fillColor: "#b0e203", baseline: "middle", align: "center"},
        // text :      "PLAY",
        marginTop : tgfScale(0),
        onClick :   function(comp)
        {
            if(!context.lockPlay){
                context.onPlayPressed.call(context);
                tgfHooks.execute("showAd");
            }
        }
    });
    
    this.container.addComponent(this.customStartButtonComponent);

    this.version = gameSettings().game.version;//window["_version"] || 'dev';

    if(this.version){
        this.ver = new tgfComponents.Label(
		{
			text: "ver: " + this.version,
            font: {fontFace: f_bitdust2.fontFace, fontSize: 16, fillColor: "#23321a", baseline: "middle", align: "left"},
            align: "center",
            x: -tgfScale(tgfGraphics.areaWidth / 2) + tgfScale(10),
			y: (-tgfScale(tgfGraphics.areaHeight / 2) + tgfScale(20)),
			onClick: function(comp){
				//context.hack = true;
			}
		});

        this.container.addComponent(this.ver);
    }

    // Add the additional components
    for (var i = 0; i < this.__components.length; i += 1)
    {
        this.container.addComponent(this.__components[i]);
    }

    this.addComponent(this.container);
};

// Processing required when freeing the dialog from use
tgfDialogs.GameStart.prototype.doFree = function() 
{
    "use strict";
    this.playButtonComponent = undefined;
};

tgfDialogs.GameStart.prototype.doShow = function()
{
    "use strict";
    this.onSpeedSelected(this.speedButtonsInactive[this.selectedSpeed]);
    this.showCollection(this.selectedSnake);

    this.buttonSoundOff.isVisible = tgfSettings.game.muted;
    this.buttonSoundOn.isVisible = !tgfSettings.game.muted;

    if(this.selectedSnake === 0){
        this.previousButton.hide();
    } else if(this.selectedSnake === this.snakeIcons.length - 1){
        this.nextButton.hide();
    }
};

tgfDialogs.GameStart.prototype.doHide = function() {
    "use strict";
    if(this.currentEggHatched > -1){
        this.snakeCollection["snakes"][this.currentEggHatched]["unlocked"] = false;
    }
};

