/////////////////////////////////////////////////////////////
// LevelController
//
// This token globally controls a level (run of the game)
//
// Copyright 2014 Tingly Games
// Last Changed: 30-5-2014

//same as before with some added Poki callbacks

// Start the level when the level start overlay is gone
LevelController.prototype._startLevel = function() {
	"use strict";
	this.initNewLevel(SkinController.skin);
	this.walls = new Walls();

	this.active = true;
	Snake.mode = Snake.gameModeStarted;
	Snake.startLevel();

	this.collectibleController = new CollectibleController();

	this._addUiElements();

	this.collectibleController.init();

	Snake.initGoal();
	Snake.initScore();

	PokiSDK['gameplayStart']();
};

// End the level when the game is over
LevelController.prototype._endLevel = function(won){
	"use strict";

	var self = this;
	this.active = false;
	this.collectibleController.active = false;

	if(Snake.score.getValue() >= Snake.highscore.getValue()){
		this.saveFile.snakes[this.levelIdx].highscore = Snake.score.getValue();
	}

	tgfHooks.execute("gameCompleted", this.levelIdx, Snake.score.getValue());
	this.saveData();

	this.date = new Date();

	this.timeFinished = this.date.getTime();

	var playSession = this.timeFinished - this.timeStart;

	ContollerUsage.used();

	this.gameOverDialog = new tgfDialogs.GameEnd
	({
		ranks   : self.ranks,
		points  : Snake.score.getValue(),
	});
	
	PokiSDK['gameplayStop']();

	tgfHooks.execute("showAd", function(){
		self.gameOverDialog.show();
	});

	
};
